const STAR_SVG = '<svg viewBox="0 0 24 24"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87L18.18 22 12 18.27 5.82 22 7 14.14 2 9.27l6.91-1.01z"/></svg>';

// ==================== STATE ====================
let state = ClassmatesAppState.createDefaultState();

function getCurrentPupil(){return ClassmatesShell.getCurrentPupil()}
function setCurrentPupil(name){return ClassmatesShell.setCurrentPupil(name)}
function clearCurrentPupil(){return ClassmatesShell.clearCurrentPupil()}
function stateKey(){return ClassmatesAppState.getStateKey(getCurrentPupil())}
function loadState(){state=ClassmatesAppState.loadState(getCurrentPupil())}
function saveState(){state=ClassmatesAppState.saveState(getCurrentPupil(),state)}
function loadPupilState(name){return ClassmatesAppState.loadState(name)}
function updateStreak(){state=ClassmatesAppState.updateStreak(state)}
function recordPlay(){state=ClassmatesAppState.applyPlayProgress(state);checkAch('games_25',state.games>=25);checkAch('games_100',state.games>=100);saveState()}
function addStars(n){state=ClassmatesAppState.applyStars(state,n);checkAch('stars_50',state.stars>=50);checkAch('stars_100',state.stars>=100);saveState()}
function checkAch(id,cond){if(cond&&!state.achievements.includes(id)){state.achievements.push(id);saveState();showAchPopup(id);return true}return false}
function resetProgress(){if(confirm('This will delete all your stars, badges and progress. Are you sure?')){state=ClassmatesAppState.resetState(getCurrentPupil());updateHomeStats()}}

// ==================== NAVIGATION ====================
function showScreen(id){ClassmatesShell.showScreen(id)}
function toggleSection(header){header.classList.toggle('collapsed');const grid=header.nextElementSibling;if(grid&&grid.classList.contains('subject-grid'))grid.classList.toggle('collapsed')}
function goHome(){showScreen('home');updateHomeStats()}
const GAME_CATS={spelling:'literacy',dictation:'literacy',vowels:'literacy',anagram:'literacy',phonics:'literacy',wordfam:'literacy',sentence:'literacy',punctuation:'literacy',vocab:'literacy',reading:'literacy',grammar:'literacy',rhyme:'literacy',maths:'numeracy',times:'numeracy',speed:'numeracy',bonds:'numeracy',missnum:'numeracy',placeval:'numeracy',telltime:'numeracy',money:'numeracy',fractions:'numeracy',wordprob:'numeracy',shapes:'numeracy',datahandling:'numeracy',measure:'numeracy',sequence:'numeracy',capitals:'geography',continents:'geography',weather:'geography',compass:'geography',flags:'geography',daily:'challenge',h2h:'challenge',memorymatch:'challenge',spellingbee:'challenge',scotquiz:'challenge',typing:'challenge',customquiz:'challenge',hdash:'challenge'};
function startGame(g){const el=document.getElementById(g);const currentPupil=getCurrentPupil();if(el){el.classList.remove('cat-literacy','cat-numeracy','cat-geography','cat-challenge');const cat=GAME_CATS[g];if(cat)el.classList.add('cat-'+cat)}showScreen(g);if(g==='times')renderTTSelect();if(g==='daily')initDaily();if(g==='memorymatch')startMemoryMatch();if(g==='spellingbee')startBee();if(g==='scotquiz')startScotQuiz();if(g==='typing')startTyping();if(g==='customquiz')startCustomQuiz();if(g==='compass')startCompass();if(g==='flags')startFlags();if(g==='hdash')hdashInit();highlightRecommended(g,g);if(currentPupil){const gh=document.querySelector('#'+g+' .game-header');if(gh){let avEl=gh.querySelector('.game-avatar');if(!avEl){avEl=document.createElement('span');avEl.className='game-avatar';gh.appendChild(avEl)}avEl.innerHTML=renderAvatarSVG(getAvatarData(currentPupil),32)}}}
function updateHomeStats(){const currentPupil=getCurrentPupil();animateCounter(document.getElementById('statStars'),state.stars,600);animateCounter(document.getElementById('statGames'),state.games,600);const streakEl=document.getElementById('statStreak');if(state.streak>=3){streakEl.innerHTML=state.streak+' <span class="streak-flame">\u{1F525}</span>'}else{streakEl.textContent=state.streak}updateCoinDisplay();renderBadges();renderShop();renderProgressMap();renderWeeklyGoal();ClassmatesPupilShell.renderHomeHeader({pupilName:currentPupil,avatarMarkup:currentPupil?renderAvatarSVG(getAvatarData(currentPupil),36):'',greeting:getGreeting(),dayMessage:getDayMessage()});renderLeaderboard();if(typeof ClassmatesPupilShell.renderSuggestedGame==='function'){ClassmatesPupilShell.renderSuggestedGame(document.getElementById('suggestedGame'),state)}const cqCard=document.getElementById('customQuizCard');if(cqCard)cqCard.style.display=ClassmatesTeacherAuthoring.hasCustomQuiz()?'':'none';renderAssignmentBanner()}
function renderLeaderboard(){ClassmatesPupilShell.renderLeaderboard({currentPupil:getCurrentPupil(),pupils:getPupils(),loadPupilState:loadPupilState})}
function renderProgressMap(){const pm=document.getElementById('progressMap');if(!pm)return;const topics=[{id:'spelling',name:'Spelling',color:'#f7971e'},{id:'maths',name:'Maths',color:'#0083b0'},{id:'times',name:'Tables',color:'#e44d26'},{id:'reading',name:'Reading',color:'#56ab2f'},{id:'bonds',name:'Bonds',color:'#11998e'},{id:'phonics',name:'Phonics',color:'#0abde3'}];let h='';topics.forEach(t=>{const lv=state.adaptive&&state.adaptive[t.id]?state.adaptive[t.id].level:1;const pct=lv/3*100;h+='<div class="pmap-row"><span class="pmap-label">'+t.name+'</span><div class="pmap-bar"><div class="pmap-fill" style="width:'+pct+'%;background:'+t.color+'"></div></div><span class="pmap-level">Lv'+lv+'</span></div>'});pm.innerHTML=h}
function renderBadges(){const r=document.getElementById('badgesRow');r.innerHTML='';ACHIEVEMENTS.forEach(a=>{const e=state.achievements.includes(a.id);const d=document.createElement('div');d.className='badge'+(e?' earned':' locked');d.style.background=e?a.bg:'';d.innerHTML=a.icon+'<span class="badge-tip">'+a.name+(e?'':' (locked)')+'</span>';r.appendChild(d)})}

// ==================== LANDING PAGE ====================
function showStaffLogin(){document.getElementById('staffModal').classList.add('show');document.getElementById('staffPwd').value='';document.getElementById('staffError').textContent='';setTimeout(()=>document.getElementById('staffPwd').focus(),100)}
function hideStaffLogin(){document.getElementById('staffModal').classList.remove('show')}
function checkStaffPwd(){const pwd=document.getElementById('staffPwd').value;if(pwd===getStaffPwd()){hideStaffLogin();showScreen('teacher');renderTeacher()}else{document.getElementById('staffError').textContent='Incorrect password';document.getElementById('staffPwd').classList.add('shake');setTimeout(()=>document.getElementById('staffPwd').classList.remove('shake'),300)}}
function enterPupilHome(){const pupils=getPupils();if(pupils.length>0){renderPupilGrid();showScreen('pupilselect')}else{clearCurrentPupil();loadState();showScreen('home');updateHomeStats()}}
function createPupilShellOptions(){return{currentPupil:getCurrentPupil(),pupils:getPupils(),getAvatarData:getAvatarData,hasAvatar:ClassmatesAvatar.hasAvatar,renderAvatarSVG:renderAvatarSVG,onSelectPupil:selectPupil,onEditAvatar:function(name){setCurrentPupil(name);ClassmatesAvatar.prepareAvatarForPupil(name);showScreen('avatarbuilder');renderAvatarBuilder()},onStartPupil:function(name){setCurrentPupil(name);ClassmatesAvatar.prepareAvatarForPupil(name);loadState();showScreen('home');updateHomeStats()},onPlayGuest:function(){clearCurrentPupil();loadState();showScreen('home');updateHomeStats()}}}
function renderPupilSelect(){return ClassmatesPupilShell.renderPupilSelect(createPupilShellOptions())}
function selectPupil(name){setCurrentPupil(name);loadState();renderPupilGrid();updateHomeStats()}

// ==================== PUPIL MANAGER ====================
function getPupils(){return ClassmatesPupils.listPupils()}
function savePupils(list){return ClassmatesPupils.savePupils(list)}
function addPupil(){const inp=document.getElementById('newPupilInput');const result=ClassmatesPupils.addPupil(inp.value);if(!result.name)return;inp.value='';renderPupilList();renderPupilSelect()}
function bulkAddPupils(){const input=prompt('Paste pupil names (one per line or comma-separated):');if(!input)return;const names=input.split(/[\n,]+/).map(n=>n.trim()).filter(n=>n.length>0);const result=ClassmatesPupils.addPupils(names);renderPupilList();renderPupilSelect();alert(result.added+' pupils added.')}
function removePupil(name){if(!confirm('Remove '+name+' and their progress?')){return}ClassmatesPupils.removePupil(name);renderPupilList();renderPupilSelect();renderBackupPanel()}
function resetPupilProgress(name){if(!confirm('Reset all progress for '+name+'?'))return;ClassmatesPupils.resetPupilProgress(name);renderTeacher();renderBackupPanel()}
function renderPupilList(){const el=document.getElementById('pupilList');const pupils=getPupils();if(pupils.length===0){el.innerHTML='<p style="color:#b2bec3;font-size:0.85rem;">No pupils added yet.</p>';return}el.innerHTML='';pupils.forEach(p=>{const esc=p.replace(/'/g,"\\'");const row=document.createElement('div');row.className='pupil-row';row.innerHTML='<span class="pupil-name">'+p+'</span><div style="display:flex;gap:6px;"><button class="teacher-btn grey" style="font-size:0.75rem" onclick="resetPupilProgress(\''+esc+'\')">Reset</button><button class="teacher-btn red" style="font-size:0.75rem" onclick="removePupil(\''+esc+'\')">Remove</button></div>';el.appendChild(row)})}

// ==================== TEACHER DASHBOARD ====================
function showTeacherTab(tabId,btn){document.querySelectorAll('.teacher-page').forEach(p=>p.classList.remove('active'));document.querySelectorAll('.teacher-tab').forEach(t=>t.classList.remove('active'));document.getElementById('tp-'+tabId).classList.add('active');if(btn)btn.classList.add('active');if(tabId==='progress')renderProgressTable();if(tabId==='overview')renderClassSummary();if(tabId==='settings'){document.getElementById('schoolNameInput').value=getSchoolName();renderBackupPanel()}if(tabId==='assign'){const assignment=ClassmatesTeacherAuthoring.getAssignmentFormState();document.getElementById('assignActivity').value=assignment.activity;document.getElementById('assignLevel').value=assignment.level;document.getElementById('assignMessage').value=assignment.message}}
// ==================== PUPIL DETAIL ====================
let detailPupil=null;
function escapeHtml(value){return String(value==null?'':value).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;')}
function showPupilDetail(name){detailPupil=name;const detail=ClassmatesTeacherSummary.getPupilDetail(name);const sec=document.getElementById('pupilDetailSection');sec.style.display='block';document.getElementById('pupilDetailTitle').textContent=detail.title;let h='<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:10px;margin-bottom:16px">';detail.stats.forEach(stat=>{h+='<div class="stat-card"><span class="sc-val">'+escapeHtml(stat.value)+'</span><span class="sc-label">'+escapeHtml(stat.label)+'</span></div>'});h+='</div>';if(window.ClassmatesMastery){const overview=ClassmatesMastery.getPupilOverview(name);if(overview.packMasteries.length>0){h+='<div style="margin-top:12px"><strong style="font-size:0.85rem;color:#1a2332">Flagship Mastery:</strong><div style="display:flex;flex-direction:column;gap:6px;margin-top:6px">';overview.packMasteries.forEach(pack=>{var statusColor=pack.status==='Secure'?'#00b894':pack.status==='Needs support'?'#e74c3c':'#fdcb6e';h+='<div style="display:flex;justify-content:space-between;align-items:center;background:#f8f9fa;border-radius:8px;padding:6px 10px;border-left:3px solid '+escapeHtml(pack.accent)+'"><div><span style="font-weight:700;font-size:0.8rem;color:#2d3436">'+escapeHtml(pack.packTitle)+'</span><span style="font-size:0.7rem;color:#636e72;margin-left:6px">'+escapeHtml(pack.stageBand)+'</span></div><div style="display:flex;gap:8px;align-items:center"><span style="font-size:0.75rem;font-weight:700;color:'+statusColor+'">'+escapeHtml(pack.accuracy)+'%</span><span style="font-size:0.7rem;color:#8899aa">'+escapeHtml(pack.recentTrend)+'</span><span style="font-size:0.65rem;padding:2px 6px;border-radius:4px;background:'+statusColor+';color:white;font-weight:700">'+escapeHtml(pack.status)+'</span></div></div>'});h+='</div></div>'}if(overview.packMasteries.some(p=>p.commonErrors.length>0)){h+='<div style="margin-top:8px"><strong style="font-size:0.85rem;color:#1a2332">Common Errors:</strong><div style="display:flex;flex-wrap:wrap;gap:6px;margin-top:4px">';overview.packMasteries.forEach(pack=>{pack.commonErrors.forEach(err=>{h+='<span style="background:#ffeef0;padding:3px 8px;border-radius:6px;font-size:0.7rem;color:#e74c3c;font-weight:600">'+escapeHtml(err.label)+' ('+escapeHtml(err.count)+')</span>'})});h+='</div></div>'}}if(detail.adaptiveTopics.length>0){h+='<div style="margin-top:12px"><strong style="font-size:0.85rem;color:#1a2332">Adaptive Levels:</strong><div style="display:flex;flex-wrap:wrap;gap:8px;margin-top:6px">';detail.adaptiveTopics.forEach(topic=>{h+='<span style="background:#e4e8ec;padding:4px 10px;border-radius:8px;font-size:0.75rem;font-weight:700;color:#4a5568">'+escapeHtml(topic.topic)+': Lv'+escapeHtml(topic.level)+'</span>'});h+='</div></div>'}if(detail.achievements.length>0){h+='<div style="margin-top:12px"><strong style="font-size:0.85rem;color:#1a2332">Badges Earned:</strong><div style="margin-top:6px;font-size:0.8rem;color:#4a5568">'+escapeHtml(detail.achievements.join(', '))+'</div></div>'}h+='<div style="margin-top:8px;font-size:0.8rem;color:#8899aa">Last active: '+escapeHtml(detail.lastActiveLabel)+'</div>';if(detail.sessionHistory&&detail.sessionHistory.length>0){h+='<div style="margin-top:16px"><strong style="font-size:0.85rem;color:#1a2332">Recent Sessions:</strong><div style="display:flex;flex-direction:column;gap:8px;margin-top:8px">';detail.sessionHistory.forEach(session=>{h+='<div style="background:#f5f6f7;border-radius:8px;padding:8px 10px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px"><span style="font-weight:700;font-size:0.75rem;color:#2d3436">'+escapeHtml(session.displayDate)+'</span><span style="font-size:0.7rem;color:#8899aa">'+escapeHtml(session.dailyStats.gamesPlayed)+' games</span></div><div style="display:flex;gap:8px;flex-wrap:wrap">';session.games.forEach(game=>{h+='<span style="background:#e8f5f5;padding:2px 6px;border-radius:4px;font-size:0.65rem;color:#0c5a5c;font-weight:600">'+escapeHtml(game.title)+': '+escapeHtml(game.correct)+'/'+escapeHtml(game.total)+'</span>'});h+='</div><div style="margin-top:4px;font-size:0.7rem;color:#636e72">Accuracy: '+escapeHtml(session.dailyStats.accuracy)+'% | Stars: '+escapeHtml(session.dailyStats.starsEarned)+'</div></div>'});h+='</div></div>'}document.getElementById('pupilDetailContent').innerHTML=h;sec.scrollIntoView({behavior:'smooth'})}

function printPupilReport(){if(!detailPupil)return;const w=window.open('','_blank');if(!w)return;w.document.write(ClassmatesTeacherReports.buildPupilReportHtml(detailPupil));w.document.close();setTimeout(()=>w.print(),300)}

