function saveAssignment(){const result=ClassmatesTeacherAuthoring.saveAssignment({activity:document.getElementById('assignActivity').value,level:document.getElementById('assignLevel').value,message:document.getElementById('assignMessage').value});document.getElementById('assignStatus').innerHTML='<span style="color:'+(result.ok?'#11998e':'#e74c3c')+'">'+escapeHtml(result.ok?result.message:result.error)+'</span>';renderBackupPanel()}
function clearAssignment(){const result=ClassmatesTeacherAuthoring.clearAssignment();document.getElementById('assignActivity').value=result.state.activity;document.getElementById('assignLevel').value=result.state.level;document.getElementById('assignMessage').value=result.state.message;document.getElementById('assignStatus').innerHTML='<span style="color:#8899aa">'+escapeHtml(result.message)+'</span>';renderBackupPanel()}
function getAssignment(){return ClassmatesAssignments.getAssignment()}
function quickAssign(){var sel=document.getElementById('quickAssignGame');var status=document.getElementById('quickAssignStatus');var game=sel.value;if(!game){if(status)status.textContent='Pick a game first';return}var result=ClassmatesTeacherAuthoring.saveAssignment({activity:game,level:'2',message:''});if(result.ok){sel.value='';if(status)status.innerHTML='<span style="color:#11998e">Assigned!</span>';renderAssignmentBanner();renderBackupPanel()}else{if(status)status.innerHTML='<span style="color:#e74c3c">'+(result.error||'Failed')+'</span>'}}
function renderAssignmentBanner(){const assignment=ClassmatesTeacherAuthoring.getAssignmentBanner();const banner=document.getElementById('assignBanner');if(!assignment.visible){banner.style.display='none';return}banner.style.display='block';document.getElementById('assignBannerText').textContent=assignment.text}
function launchAssignment(){const assignment=ClassmatesTeacherAuthoring.getAssignmentBanner();if(assignment.visible&&assignment.activity)startGame(assignment.activity)}

// ==================== PASSWORD ====================
function getSchoolName(){return ClassmatesSettings.getSchoolName()}
function getStaffPwd(){return ClassmatesSettings.getStaffPassword()}
function changePassword(){const old=document.getElementById('oldPwd').value;const nw=document.getElementById('newPwd').value;const result=ClassmatesSettings.updateStaffPassword(old,nw);if(!result.ok){document.getElementById('pwdStatus').innerHTML='<span style="color:#e74c3c">'+result.error+'</span>';return}document.getElementById('pwdStatus').innerHTML='<span style="color:#11998e">Password changed!</span>';document.getElementById('oldPwd').value='';document.getElementById('newPwd').value='';renderBackupPanel()}
function saveSchoolName(){const name=document.getElementById('schoolNameInput').value.trim();if(name){const savedName=ClassmatesSettings.setSchoolName(name);document.getElementById('schoolName').textContent=savedName;renderBackupPanel()}}
function setBackupStatus(message,color){const status=document.getElementById('backupStatus');if(!status)return;status.innerHTML=message?'<span style="color:'+color+'">'+message+'</span>':''}
function renderBackupPanel(){const summary=document.getElementById('backupSummary');if(!summary)return;const pupils=getPupils();const keys=storageListAppKeys();const model=ClassmatesTeacherTools.getBackupPanelModel({storageAvailable:storageIsAvailable(),schoolName:getSchoolName(),pupilCount:pupils.length,profileCount:keys.filter(k=>k.startsWith('classmates_state_')).length,attemptCount:ClassmatesAttempts.listAttempts().length,appRecordCount:keys.length});var quotaHtml='';if(typeof storageGetUsage==='function'){var usage=storageGetUsage();if(usage.available){quotaHtml='<div style="margin-top:10px;font-size:0.8rem;color:#636e72">Storage used: <strong>'+usage.usedKB+' KB</strong></div>';if(usage.warning){quotaHtml='<div style="margin-top:10px;padding:10px 14px;background:#fff3cd;border:1px solid #ffc107;border-radius:10px"><div style="font-size:0.8rem;font-weight:700;color:#856404">Storage Warning</div><div style="font-size:0.75rem;color:#856404;margin-top:4px">Using <strong>'+usage.usedKB+' KB</strong> — approaching browser limit. Export a backup now to keep your data safe.</div><button class="teacher-btn teal" style="font-size:0.75rem;margin-top:8px" onclick="exportAppBackup()">Export Backup</button></div>'}}}summary.innerHTML=model.summaryHtml+quotaHtml;if(model.statusMessage)setBackupStatus(model.statusMessage,model.statusColor)}
function exportAppBackup(){const result=ClassmatesTeacherTools.downloadBackup({storageAvailable:storageIsAvailable(),downloadBackup:storageDownloadBackup});setBackupStatus(result.message,result.color);renderBackupPanel()}
function triggerBackupImport(){const input=document.getElementById('backupFileInput');if(input)input.click()}
async function handleBackupImport(event){const file=event.target&&event.target.files?event.target.files[0]:null;if(!file)return;const result=await ClassmatesTeacherTools.importBackupFile(file,{importBackupFile:storageImportBackupFile});try{if(result.ok){clearCurrentPupil();state=ClassmatesAppState.createDefaultState();loadState();renderPupilGrid();renderPupilSelect();renderTeacher();updateHomeStats()}setBackupStatus(result.message,result.color)}finally{if(event.target)event.target.value='';renderBackupPanel()}}

// ==================== SESSION TIMER ====================
let sessionTimerInterval=null;
function setSessionTimer(mins){clearSessionTimer();const end=Date.now()+mins*60000;document.getElementById('timerStatus').textContent='Timer set: '+mins+' minutes';sessionTimerInterval=setInterval(()=>{const left=Math.max(0,end-Date.now());if(left<=0){clearSessionTimer();alert('Time is up! '+mins+' minute practice session complete.');document.getElementById('timerStatus').textContent='Timer finished!'}},1000)}
function clearSessionTimer(){if(sessionTimerInterval){clearInterval(sessionTimerInterval);sessionTimerInterval=null}document.getElementById('timerStatus').textContent=''}

function addCustomQ(){const result=ClassmatesTeacherAuthoring.addCustomQuizQuestion({question:document.getElementById('cqQuestion').value,correct:document.getElementById('cqA').value,options:[document.getElementById('cqA').value,document.getElementById('cqB').value,document.getElementById('cqC').value,document.getElementById('cqD').value]});if(!result.ok)return alert(result.error);['cqQuestion','cqA','cqB','cqC','cqD'].forEach(id=>document.getElementById(id).value='');renderCQList();updateHomeStats();renderBackupPanel()}
function renderCQList(){const el=document.getElementById('cqList');const quiz=ClassmatesTeacherAuthoring.listCustomQuizQuestions();if(quiz.length===0){el.innerHTML='<p style="color:#8899aa;font-size:0.8rem">No questions yet.</p>';return}el.innerHTML=quiz.map(item=>'<div class="pupil-row"><span class="pupil-name" style="font-size:0.8rem">'+escapeHtml(item.question)+'</span><button class="teacher-btn red" style="font-size:0.7rem" onclick="removeCustomQ('+item.index+')">Remove</button></div>').join('')}
function removeCustomQ(i){ClassmatesTeacherAuthoring.removeCustomQuizQuestion(i);renderCQList();updateHomeStats();renderBackupPanel()}
function renderTeacher(){renderPupilList();renderClassSummary();renderProgressTable();renderCQList();const sn=getSchoolName();document.getElementById('schoolName').textContent=sn;const pc=document.getElementById('pupilCount');if(pc)pc.textContent=getPupils().length+' pupils registered';renderBackupPanel();showTeacherTab('overview',document.querySelector('.teacher-tab'))}
function renderClassSummary(){const el=document.getElementById('classSummary');const home=ClassmatesTeacherSummary.getTeacherHomeModel();const summary=home.classSummary;if(summary.pupilCount===0){el.innerHTML='';return}let h='';if(typeof storageNeedsBackupReminder==='function'&&storageNeedsBackupReminder()){h+='<div style="background:#fff8e1;border:1px solid #ffe082;border-radius:12px;padding:12px 16px;margin-bottom:12px;display:flex;justify-content:space-between;align-items:center"><div><div style="font-size:0.8rem;font-weight:700;color:#f57f17">Backup Reminder</div><div style="font-size:0.75rem;color:#795548">It has been a while since your last backup. Export to keep data safe.</div></div><button class="teacher-btn teal" style="font-size:0.75rem;white-space:nowrap" onclick="exportAppBackup()">Export Now</button></div>'}h+='<div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:16px">';summary.cards.forEach(card=>{h+='<div style="background:'+card.background+';border-radius:12px;padding:10px 16px;flex:1;min-width:100px;text-align:center"><div style="font-family:Fredoka One,Comic Sans MS,cursive;font-size:1.3rem;color:'+card.color+'">'+escapeHtml(card.value)+'</div><div style="font-size:0.7rem;color:#636e72;font-weight:700">'+escapeHtml(card.label)+'</div></div>'});h+='</div>';if(home.classMastery&&home.classMastery.totalPupils>0){var cm=home.classMastery;h+='<div style="background:#e8f5e9;border-radius:12px;padding:12px 16px;margin-bottom:12px"><div style="font-size:0.8rem;font-weight:700;color:#2e7d32;margin-bottom:8px">Class Mastery Overview</div><div style="display:flex;gap:16px;flex-wrap:wrap;font-size:0.8rem"><div><span style="font-weight:700;color:#2d3436">'+escapeHtml(cm.avgAccuracy)+'%</span> <span style="color:#636e72">avg accuracy</span></div><div><span style="font-weight:700;color:#e74c3c">'+escapeHtml(cm.pupilsNeedingSupport)+'</span> <span style="color:#636e72">need support</span></div></div>';if(cm.topPack){h+='<div style="margin-top:6px;font-size:0.75rem;color:#636e72">Strongest: <strong style="color:#2e7d32">'+escapeHtml(cm.topPack.packTitle)+' ('+escapeHtml(cm.topPack.accuracy)+'%)</strong></div>'}if(cm.weakestPack){h+='<div style="font-size:0.75rem;color:#636e72">Weakest: <strong style="color:#e74c3c">'+escapeHtml(cm.weakestPack.packTitle)+' ('+escapeHtml(cm.weakestPack.accuracy)+'%)</strong></div>'}h+='</div>'}if(home.needsAttention.length>0){h+='<div style="background:#fff5f5;border-radius:12px;padding:12px 16px;margin-bottom:12px"><div style="font-size:0.8rem;font-weight:700;color:#c0392b;margin-bottom:8px">Needs Attention</div>';home.needsAttention.forEach(a=>{h+='<div style="display:flex;justify-content:space-between;align-items:center;padding:4px 0;font-size:0.8rem"><span style="font-weight:600;color:#2d3436">'+escapeHtml(a.name)+'</span><span style="color:#e17055;font-size:0.75rem">'+escapeHtml(a.reason)+'</span></div>'});h+='</div>'}if(home.interventions.length>0){h+='<div style="background:#fff8e6;border-radius:12px;padding:12px 16px;margin-bottom:12px"><div style="font-size:0.8rem;font-weight:700;color:#d4a520;margin-bottom:8px">Mastery Signals</div>';home.interventions.forEach(s=>{var statusColor=s.status==='Needs support'?'#e74c3c':'#e17055';h+='<div style="display:flex;justify-content:space-between;align-items:center;padding:4px 0;font-size:0.8rem"><span style="font-weight:600;color:#2d3436">'+escapeHtml(s.pupilName)+' — '+escapeHtml(s.packTitle)+'</span><span style="color:'+statusColor+';font-size:0.75rem">'+escapeHtml(s.accuracy)+'% '+escapeHtml(s.recentTrend)+'</span></div>'});h+='</div>'}if(home.recentActivity.length>0){h+='<div style="background:#f0ecff;border-radius:12px;padding:12px 16px;margin-bottom:12px"><div style="font-size:0.8rem;font-weight:700;color:#6c5ce7;margin-bottom:8px">Recent Activity</div>';home.recentActivity.forEach(a=>{h+='<div style="display:flex;justify-content:space-between;align-items:center;padding:4px 0;font-size:0.8rem"><span style="font-weight:600;color:#2d3436">'+escapeHtml(a.pupilName)+'</span><span style="color:#636e72;font-size:0.75rem">'+escapeHtml(a.packTitle)+' — '+escapeHtml(a.correct)+'/'+escapeHtml(a.total)+'</span></div>'});h+='</div>'}el.innerHTML=h}
function editSchoolName(){const name=prompt('School name:',document.getElementById('schoolName').textContent);if(name){const savedName=ClassmatesSettings.setSchoolName(name);document.getElementById('schoolName').textContent=savedName;renderBackupPanel()}}
function renderProgressTable(){const area=document.getElementById('progressArea');const headers=ClassmatesTeacherSummary.getProgressHeaders();const rows=ClassmatesTeacherSummary.listProgressRows();if(rows.length===0){area.innerHTML='<p style="color:#b2bec3;font-size:0.85rem;">No pupils added yet. Add pupil names above to track progress.</p>';return}let sortCol=0,sortDir=1;function renderTable(){let h='<div class="progress-table-wrap"><table class="progress-table"><thead><tr>';headers.forEach((hd,i)=>{h+='<th data-col="'+i+'">'+escapeHtml(hd)+(sortCol===i?(sortDir===1?' &#x25B2;':' &#x25BC;'):'')+'</th>'});h+='</tr></thead><tbody>';const sorted=[...rows].sort((a,b)=>{const va=typeof a.cells[sortCol]==='number'?a.cells[sortCol]:String(a.cells[sortCol]).toLowerCase();const vb=typeof b.cells[sortCol]==='number'?b.cells[sortCol]:String(b.cells[sortCol]).toLowerCase();if(va<vb)return -sortDir;if(va>vb)return sortDir;return 0});sorted.forEach(row=>{h+='<tr>';row.cells.forEach((cell,index)=>{if(index===0){h+='<td style="cursor:pointer;color:#11998e;font-weight:700" onclick="showPupilDetail(\''+String(row.name).replace(/'/g,"\\'")+'\')">'+escapeHtml(cell)+'</td>'}else{h+='<td>'+escapeHtml(cell)+'</td>'}});h+='</tr>'});h+='</tbody></table></div>';area.innerHTML=h;area.querySelectorAll('th').forEach(th=>{th.onclick=()=>{const col=parseInt(th.dataset.col);if(sortCol===col)sortDir*=-1;else{sortCol=col;sortDir=1}renderTable()}})}renderTable()}
function printReport(){const w=window.open('','_blank');if(!w)return;w.document.write(ClassmatesTeacherReports.buildClassReportHtml());w.document.close();setTimeout(()=>w.print(),300)}
function exportCSV(){const csv=ClassmatesTeacherReports.buildProgressCsv();const blob=new Blob([csv],{type:'text/csv'});const a=document.createElement('a');const url=URL.createObjectURL(blob);a.href=url;a.download=ClassmatesTeacherReports.createCsvFileName();a.click();setTimeout(()=>URL.revokeObjectURL(url),0)}
function resetAllData(){if(!confirm('This will delete ALL pupil data and progress. This cannot be undone.'))return;if(!confirm('Are you absolutely sure?'))return;storageClearAppData();clearCurrentPupil();state=ClassmatesAppState.createDefaultState();renderPupilGrid();renderPupilSelect();updateHomeStats();renderTeacher();setBackupStatus('All local Classmates data was cleared from this device.','#8899aa')}

// ==================== SPELLING ====================
let sp={level:1,words:[],idx:0,word:'',revealed:[],lives:0,maxLives:6,correct:0,total:10,hintUsed:false,missed:[]};

function setSpellingLevel(lv){sp.level=lv;sp.maxLives=lv===1?7:lv===2?6:5;var spellingWords=getSpellingWords();var adaptiveLevel=state&&state.adaptive&&state.adaptive.spelling?state.adaptive.spelling.level:lv;var weak=getWeakItems('spelling',3);var pool=[...spellingWords[lv]];if(adaptiveLevel>lv&&spellingWords[Math.min(lv+1,3)]){var harder=spellingWords[Math.min(lv+1,3)];shuffle(harder=[...harder]);pool=pool.concat(harder.slice(0,Math.ceil(sp.total*0.3)))}else if(adaptiveLevel<lv&&lv>1&&spellingWords[lv-1]){var easier=spellingWords[lv-1];shuffle(easier=[...easier]);pool=pool.concat(easier.slice(0,Math.ceil(sp.total*0.2)))}shuffle(pool);var fresh=pool.filter(w=>!weak.find(wk=>wk.w===w.w)).slice(0,sp.total-weak.length);sp.words=[...weak,...fresh];shuffle(sp.words);sp.idx=0;sp.correct=0;sp.missed=[];hide('spellingLevelSelect');show('spellingGame');loadSpellWord()}
function loadSpellWord(){const item=sp.words[sp.idx];sp.word=item.w.toLowerCase();sp.revealed=new Array(sp.word.length).fill(false);sp.lives=sp.maxLives;sp.hintUsed=false;const pic=document.getElementById('spellPic');const eFn=WORD_EMOJI[sp.word];if(eFn&&EMOJI_SVG[eFn]){pic.innerHTML=EMOJI_SVG[eFn];pic.style.display=''}else{pic.textContent='?';pic.style.display=''};document.getElementById('spellHint').textContent=item.h;document.getElementById('hintBtn').style.display='none';updateSpellProgress();renderSpellWord();renderLives();renderKeyboard();animateQuestion('spellWord');var elWrap=document.getElementById('extraLifeWrap');if(elWrap)elWrap.style.display=getPowerupCount('extra_life')>0?'':'none';var rlBtn=document.getElementById('revealLetterBtn');if(rlBtn)rlBtn.style.display=getPowerupCount('reveal_letter')>0?'inline-block':'none'}
function updateSpellProgress(){document.getElementById('spellProgress').style.width=(sp.idx/sp.total*100)+'%';document.getElementById('spellProgressText').textContent='Word '+(sp.idx+1)+' of '+sp.total}
function renderSpellWord(){const el=document.getElementById('spellWord');el.innerHTML='';for(let i=0;i<sp.word.length;i++){const s=document.createElement('div');s.className='letter-slot'+(sp.revealed[i]?' revealed':'');s.textContent=sp.revealed[i]?sp.word[i]:'';el.appendChild(s)}}
function renderLives(){const el=document.getElementById('spellLives');el.innerHTML='';for(let i=0;i<sp.maxLives;i++){const d=document.createElement('div');d.className='life'+(i>=sp.lives?' lost':'');d.innerHTML='<div class="life-heart"></div>';el.appendChild(d)}}
function renderKeyboard(){const rows=['qwertyuiop','asdfghjkl','zxcvbnm'];const kb=document.getElementById('keyboard');kb.innerHTML='';rows.forEach(row=>{const r=document.createElement('div');r.className='kb-row';for(const ch of row){const k=document.createElement('button');k.className='kb-key';k.textContent=ch;k.id='key_'+ch;k.onclick=()=>pressKey(ch);r.appendChild(k)}kb.appendChild(r)})}
function pressKey(ch){const btn=document.getElementById('key_'+ch);if(!btn||btn.classList.contains('correct')||btn.classList.contains('wrong'))return;let found=false;for(let i=0;i<sp.word.length;i++){if(sp.word[i]===ch&&!sp.revealed[i]){sp.revealed[i]=true;found=true}}if(found){btn.classList.add('correct');sfxClick()}else{btn.classList.add('wrong');sp.lives--;renderLives();document.getElementById('spellWord').classList.add('shake');setTimeout(()=>document.getElementById('spellWord').classList.remove('shake'),300)}renderSpellWord();if(sp.revealed.every(r=>r)){sp.correct++;state.spellingCorrect++;sfxCorrect();checkAch('spell_10',state.spellingCorrect>=10);checkAch('spell_50',state.spellingCorrect>=50);saveState();setTimeout(nextSpellWord,800)}else if(sp.lives<=0){sfxWrong();sp.missed.push({w:sp.word,h:sp.words[sp.idx].h});sp.revealed=sp.revealed.map(()=>true);renderSpellWord();document.querySelectorAll('.letter-slot').forEach(s=>{s.classList.remove('revealed');s.classList.add('wrong-reveal')});setTimeout(nextSpellWord,1200)}}
function showHint(){if(!sp.hintUsed){sp.hintUsed=true;document.getElementById('spellHint').textContent=sp.words[sp.idx].h;document.getElementById('hintBtn').style.display='none'}}
function useExtraLife(){if(usePowerup('extra_life')){sp.maxLives++;sp.lives++;renderLives();var elWrap=document.getElementById('extraLifeWrap');if(getPowerupCount('extra_life')<=0&&elWrap)elWrap.style.display='none';sfxClick()}}
function useRevealLetter(){var unrevealed=[];for(var i=0;i<sp.word.length;i++){if(!sp.revealed[i])unrevealed.push(i)}if(unrevealed.length===0)return;if(usePowerup('reveal_letter')){var ri=unrevealed[Math.floor(Math.random()*unrevealed.length)];sp.revealed[ri]=true;renderSpellWord();var ch=sp.word[ri];var btn=document.getElementById('key_'+ch);if(btn&&!btn.classList.contains('correct')&&!btn.classList.contains('wrong')){var allRevealed=true;for(var j=0;j<sp.word.length;j++){if(sp.word[j]===ch&&!sp.revealed[j])allRevealed=false}if(allRevealed)btn.classList.add('correct')}if(getPowerupCount('reveal_letter')<=0){var rlBtn=document.getElementById('revealLetterBtn');if(rlBtn)rlBtn.style.display='none'}if(sp.revealed.every(function(r){return r})){sp.correct++;state.spellingCorrect++;sfxCorrect();saveState();setTimeout(nextSpellWord,800)}else{sfxClick()}}}
function nextSpellWord(){sp.idx++;if(sp.idx>=sp.total)finishSpelling();else loadSpellWord()}
function finishSpelling(){show('spellingLevelSelect');hide('spellingGame');const pct=sp.correct/sp.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;if(pct===1)checkAch('perfect_spell',true);checkAch('first_game',true);if(pct>=0.8)adaptiveCorrect('spelling');else if(pct<0.4)adaptiveWrong('spelling');sp.missed.forEach(m=>recordWeak('spelling',m));addStars(stars);recordPlay();showResults('#f7971e','Aa','Spelling Done!','Level '+sp.level,stars,sp.correct,sp.total,()=>{showScreen('spelling')},sp.missed)}

// ==================== MATHS ====================
let ma={level:1,idx:0,total:10,correct:0,answer:'',question:null};

function setMathsLevel(lv){ma.level=lv;ma.idx=0;ma.correct=0;ma.answer='';ma.streak=0;ma.bestStreak=0;var adaptiveLv=state&&state.adaptive&&state.adaptive.maths?state.adaptive.maths.level:lv;ma.adaptiveLevel=Math.min(Math.max(adaptiveLv,1),3);hide('mathsLevelSelect');show('mathsGame');renderNumpad('numpad',numpadPress);loadMathQ()}
function getMathQuestionGenerator(){const mathsApi=window.ClassmatesMaths;return mathsApi&&typeof mathsApi.genMathQuestion==='function'?mathsApi.genMathQuestion:genMathQLocal}
function genMathQLocal(lv){let a,b,op,ans;if(lv===1){op=Math.random()<.5?'+':'-';if(op==='+'){a=rand(1,9);b=rand(1,10-a);ans=a+b}else{a=rand(2,10);b=rand(1,a);ans=a-b}}else if(lv===2){const r=Math.random();if(r<.4){op='+';a=rand(1,15);b=rand(1,20-a);ans=a+b}else if(r<.8){op='-';a=rand(5,20);b=rand(1,a);ans=a-b}else{op='\u00D7';a=rand(2,5);b=rand(2,5);ans=a*b}}else{const r=Math.random();if(r<.3){op='+';a=rand(10,90);b=rand(5,100-a);ans=a+b}else if(r<.6){op='-';a=rand(20,100);b=rand(5,a);ans=a-b}else if(r<.85){op='\u00D7';a=rand(2,12);b=rand(2,12);ans=a*b}else{ans=rand(2,12);b=rand(2,12);a=ans*b;op='\u00F7'}}return{text:a+' '+op+' '+b+' = ?',answer:ans}}
function genMathQ(lv){return getMathQuestionGenerator()(lv)}
function loadMathQ(){var qLevel=ma.level;if(ma.adaptiveLevel>ma.level&&Math.random()<0.3)qLevel=Math.min(ma.level+1,3);else if(ma.adaptiveLevel<ma.level&&Math.random()<0.2)qLevel=Math.max(ma.level-1,1);ma.question=getMathQuestionGenerator()(qLevel);ma.answer='';document.getElementById('mathQuestion').textContent=ma.question.text;document.getElementById('mathAnswer').textContent='_';const pct=(ma.idx/ma.total)*100;document.getElementById('mathProgress').style.width=pct+'%';document.getElementById('mathProgressText').textContent='Question '+(ma.idx+1)+' of '+ma.total;document.getElementById('mathFeedback').classList.remove('show');animateQuestion('mathQuestion')}
function renderNumpad(id,handler){const el=document.getElementById(id);el.innerHTML='';for(let i=1;i<=9;i++){const k=document.createElement('button');k.className='num-key';k.textContent=i;k.onclick=()=>handler(String(i));el.appendChild(k)}const clr=document.createElement('button');clr.className='num-key clear-key';clr.textContent='C';clr.onclick=()=>handler('C');el.appendChild(clr);const z=document.createElement('button');z.className='num-key';z.textContent='0';z.onclick=()=>handler('0');el.appendChild(z);const ent=document.createElement('button');ent.className='num-key enter-key';ent.textContent='\u2714';ent.onclick=()=>handler('enter');el.appendChild(ent)}
function numpadPress(v){if(v==='C')ma.answer='';else if(v==='enter'){checkMathAns();return}else{if(ma.answer.length<4)ma.answer+=v}document.getElementById('mathAnswer').textContent=ma.answer||'_'}
function checkMathAns(){if(!ma.answer)return;var ok=parseInt(ma.answer)===ma.question.answer;var fb=document.getElementById('mathFeedback');var fbc=document.getElementById('mathFeedbackContent');var encouragements=['Great!','Super!','Yes!','Brilliant!','Awesome!','Nice!','Perfect!','Wow!'];if(ok){ma.correct++;ma.streak=(ma.streak||0)+1;ma.bestStreak=Math.max(ma.bestStreak||0,ma.streak);state.mathsCorrect++;sfxCorrect();checkAch('math_10',state.mathsCorrect>=10);checkAch('math_50',state.mathsCorrect>=50);saveState();var word=encouragements[Math.floor(Math.random()*encouragements.length)];var streakText=ma.streak>=3?' Streak: '+ma.streak+'!':'';fbc.innerHTML='<div class="fb-correct"><div class="fb-icon">'+word+'</div><div class="fb-text">Correct!'+streakText+'</div></div>'}else{ma.streak=0;fbc.innerHTML='<div class="fb-wrong"><div class="fb-icon">'+ma.question.answer+'</div><div class="fb-text">The answer was '+ma.question.answer+'</div></div>'}fb.classList.add('show');setTimeout(()=>{fb.classList.remove('show');ma.idx++;if(ma.idx>=ma.total)finishMaths();else loadMathQ()},ok?800:1500)}
function finishMaths(){show('mathsLevelSelect');hide('mathsGame');const pct=ma.correct/ma.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;if(pct===1)checkAch('perfect_math',true);checkAch('first_game',true);if(pct>=0.8)adaptiveCorrect('maths');else if(pct<0.4)adaptiveWrong('maths');addStars(stars);recordPlay();showResults('#0984e3','1+2','Maths Done!','Level '+ma.level,stars,ma.correct,ma.total,()=>{showScreen('maths')})}

// ==================== TIMES TABLES ====================
let tt={table:0,questions:[],idx:0,total:12,correct:0,answer:'',startTime:0,timer:null,elapsed:0};

function renderTTSelect(){const g=document.getElementById('tableGrid');g.innerHTML='';const mix=document.createElement('button');mix.className='tt-btn';mix.style.gridColumn='1/-1';mix.style.background='linear-gradient(135deg,#e44d26,#f16529)';mix.style.color='white';mix.style.borderColor='#e44d26';mix.innerHTML='Mixed Tables';mix.onclick=()=>startTT(0);g.appendChild(mix);for(let t=2;t<=12;t++){const b=document.createElement('button');b.className='tt-btn';const pb=state.ttPersonalBests[t];b.innerHTML=t+'x<span class="tt-pb'+(pb?' has':'')+'\">'+(pb?(pb/1000).toFixed(1)+'s':'---')+'</span>';b.onclick=()=>startTT(t);g.appendChild(b)}}
function startTT(t){tt.table=t;tt.idx=0;tt.correct=0;tt.answer='';tt.streak=0;tt.questions=[];if(t===0){for(let i=0;i<12;i++){var a=rand(2,12);var b=rand(2,12);tt.questions.push({a:a,b:b,answer:a*b})}}else{for(let i=1;i<=12;i++)tt.questions.push({a:t,b:i,answer:t*i})}shuffle(tt.questions);hide('timesTableSelect');show('timesGame');var pbEl=document.getElementById('ttPB');if(pbEl){var pb=state.ttPersonalBests&&state.ttPersonalBests[t];pbEl.textContent=pb?'Your best: '+(pb/1000).toFixed(1)+'s — beat it!':'First try — set your time!';pbEl.style.display='block'}renderNumpad('ttNumpad',ttPress);tt.startTime=Date.now();tt.timer=setInterval(()=>{tt.elapsed=Date.now()-tt.startTime;document.getElementById('ttTimer').textContent=(tt.elapsed/1000).toFixed(1)+'s'},100);loadTTQ()}
function loadTTQ(){const q=tt.questions[tt.idx];tt.answer='';document.getElementById('ttQuestion').textContent=q.a+' \u00D7 '+q.b+' = ?';document.getElementById('ttAnswer').textContent='_';document.getElementById('ttProgress').style.width=(tt.idx/tt.total*100)+'%';document.getElementById('ttProgressText').textContent=(tt.idx+1)+' of '+tt.total;document.getElementById('ttFeedback').classList.remove('show')}
function ttPress(v){if(v==='C')tt.answer='';else if(v==='enter'){checkTTAns();return}else{if(tt.answer.length<4)tt.answer+=v}document.getElementById('ttAnswer').textContent=tt.answer||'_'}
function checkTTAns(){if(!tt.answer)return;var q=tt.questions[tt.idx];var ok=parseInt(tt.answer)===q.answer;var fb=document.getElementById('ttFeedback');var fbc=document.getElementById('ttFeedbackContent');if(ok){tt.correct++;tt.streak=(tt.streak||0)+1;var fast=['Quick!','Fast!','Speedy!','Lightning!'];var word=tt.streak>=3?fast[Math.floor(Math.random()*fast.length)]:'Yes!';var streakText=tt.streak>=3?' \u{1F525} '+tt.streak+' in a row!':'';fbc.innerHTML='<div class="fb-correct"><div class="fb-icon">'+word+'</div><div class="fb-text">'+q.a+' \u00D7 '+q.b+' = '+q.answer+streakText+'</div></div>'}else{tt.streak=0;fbc.innerHTML='<div class="fb-wrong"><div class="fb-icon">'+q.answer+'</div><div class="fb-text">'+q.a+' \u00D7 '+q.b+' = '+q.answer+'</div></div>'}fb.classList.add('show');setTimeout(()=>{fb.classList.remove('show');tt.idx++;if(tt.idx>=tt.total)finishTT();else loadTTQ()},ok?500:1200)}
function finishTT(){clearInterval(tt.timer);var time=tt.elapsed;show('timesTableSelect');hide('timesGame');var t=tt.table;var oldPB=state.ttPersonalBests&&state.ttPersonalBests[t]?state.ttPersonalBests[t]:null;var isNewPB=!oldPB||time<oldPB;if(isNewPB)state.ttPersonalBests[t]=time;if(!state.ttCompleted.includes(t))state.ttCompleted.push(t);checkAch('tt_complete',true);checkAch('tt_speed',time<30000);checkAch('first_game',true);var pct=tt.correct/tt.total;var stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;if(pct>=0.8)adaptiveCorrect('times');else if(pct<0.4)adaptiveWrong('times');addStars(stars);recordPlay();var subtitle=(time/1000).toFixed(1)+'s';if(isNewPB&&oldPB){var improvement=((oldPB-time)/1000).toFixed(1);subtitle+=' \u{1F3C6} NEW PB! '+improvement+'s faster!'}else if(isNewPB){subtitle+=' \u{1F3C6} New personal best!'}else if(oldPB){subtitle+=' (PB: '+(oldPB/1000).toFixed(1)+'s)'}showResults('#e44d26','3x4',(t===0?'Mixed':t+'x')+' Table Done!',subtitle,stars,tt.correct,tt.total,()=>{showScreen('times');renderTTSelect()})}

// ==================== READING ====================
let rd={level:1,storyIdx:0,questionIdx:0,correct:0,totalQ:0,story:null};

function setReadingLevel(lv){rd.level=lv;hide('readingLevelSelect');show('readingStorySelect');hide('readingGame');renderStoryList()}
function showReadingLevels(){show('readingLevelSelect');hide('readingStorySelect');hide('readingGame')}
function renderStoryList(){const list=document.getElementById('storyList');list.innerHTML='';READING[rd.level].forEach((s,i)=>{const done=state.storiesRead.includes(rd.level+'_'+i);const card=document.createElement('div');card.className='story-card';const cls=rd.level===1?'si-1':rd.level===2?'si-2':'si-3';card.innerHTML='<div class="story-icon '+cls+'">'+s.icon+'</div><div><div class="sc-title">'+s.title+'</div><div class="sc-desc">'+s.desc+'</div>'+(done?'<div class="sc-done">Completed!</div>':'')+'</div>';card.onclick=()=>startReading(i);list.appendChild(card)})}
function startReading(idx){rd.storyIdx=idx;rd.questionIdx=0;rd.correct=0;rd.story=READING[rd.level][idx];rd.totalQ=rd.story.questions.length;hide('readingStorySelect');show('readingGame');document.getElementById('readingStoryTitle').textContent=rd.story.title;document.getElementById('readingPassage').innerHTML=rd.story.text;show('readingReadBtn');hide('readingQuestion');document.getElementById('readProgress').style.width='0%';document.getElementById('readProgressText').textContent='Read the story, then answer questions'}
function readingShowQuestion(){hide('readingReadBtn');show('readingQuestion');loadReadQ()}
function loadReadQ(){const q=rd.story.questions[rd.questionIdx];document.getElementById('readProgress').style.width=(rd.questionIdx/rd.totalQ*100)+'%';document.getElementById('readProgressText').textContent='Question '+(rd.questionIdx+1)+' of '+rd.totalQ;const qa=document.getElementById('readingQA');qa.innerHTML='<div class="q-text">'+q.q+'</div>';q.a.forEach((a,i)=>{const btn=document.createElement('button');btn.className='ans-btn';btn.textContent=a;btn.onclick=()=>selectReadAns(btn,i,q.c);qa.appendChild(btn)});animateQuestion('readingQA')}
function selectReadAns(btn,sel,cor){document.querySelectorAll('#readingQA .ans-btn').forEach((o,i)=>{if(i===cor)o.classList.add('correct-ans');else if(i===sel)o.classList.add('wrong-ans');o.classList.add('disabled')});if(sel===cor)rd.correct++;setTimeout(()=>{rd.questionIdx++;if(rd.questionIdx>=rd.totalQ)finishReading();else loadReadQ()},1200)}
function finishReading(){const key=rd.level+'_'+rd.storyIdx;if(!state.storiesRead.includes(key))state.storiesRead.push(key);checkAch('read_3',state.storiesRead.length>=3);const total=Object.values(READING).reduce((s,l)=>s+l.length,0);checkAch('read_all',state.storiesRead.length>=total);checkAch('first_game',true);show('readingLevelSelect');hide('readingStorySelect');hide('readingGame');const pct=rd.correct/rd.totalQ;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;addStars(stars);recordPlay();showResults('#56ab2f','Bb','Story Complete!',rd.story.title,stars,rd.correct,rd.totalQ,()=>{showScreen('reading')},null)}

// ==================== DAILY ====================
let dy={step:0,totalSteps:5,level:2,spellWord:null,mathQ:null,readQ:null,bondsQ:null,bonusQ:null,correct:0};

function initDaily(){show('dailyLevelSelect');hide('dailyGame');var today=new Date().toDateString();var lastScore=storageGetJson('classmates_daily_last',null);var dailyStreak=storageGetJson('classmates_daily_streak',0);if(state.dailyCompleted===today){var el=document.getElementById('dailyLevelSelect');if(el){var streakMsg=dailyStreak>=3?' You have a '+dailyStreak+' day daily streak!':'';el.innerHTML='<div style="text-align:center;padding:40px 20px;"><div style="font-size:3rem;margin-bottom:12px">\u2705</div><div style="font-family:Fredoka One,Comic Sans MS,cursive;font-size:1.3rem;color:#2d3436;margin-bottom:8px">Today\'s Challenge Complete!</div><div style="color:#636e72;font-size:0.85rem;">Come back tomorrow for a new one.'+streakMsg+'</div></div>'}}else{var hint=document.getElementById('dailyHint');if(hint){var msg='';if(lastScore&&lastScore.score!==undefined){msg='Yesterday: '+lastScore.score+'/'+lastScore.total+'. ';if(lastScore.score>=lastScore.total)msg+='Perfect! Can you do it again?';else if(lastScore.score>=3)msg+='Good effort! Try for '+(lastScore.score+1)+' today.';else msg+='Let\'s do better today!'}if(dailyStreak>=2)msg+=' Daily streak: '+dailyStreak+' days!';hint.textContent=msg}}}
function dailySeed(){const d=new Date();return d.getFullYear()*10000+(d.getMonth()+1)*100+d.getDate()}
function seededRandom(seed){let s=seed;return function(){s=(s*16807+0)%2147483647;return(s-1)/2147483646}}
function startDaily(lv){const genMathQuestion=getMathQuestionGenerator();const spellingWords=getSpellingWords();const rng=seededRandom(dailySeed()+lv*1000);dy.level=lv;dy.step=0;dy.correct=0;dy.spellWord=spellingWords[lv][Math.floor(rng()*spellingWords[lv].length)];dy.mathQ=genMathQuestion(lv);const stories=READING[lv];const story=stories[Math.floor(rng()*stories.length)];const qIdx=Math.floor(rng()*story.questions.length);dy.readQ={story:story.title,q:story.questions[qIdx]};const target=lv===1?10:lv===2?20:100;dy.bondsQ=genNbQ(target);dy.bonusQ=genMathQuestion(Math.min(lv+1,3));hide('dailyLevelSelect');show('dailyGame');renderDailySteps();loadDailyStep()}
function renderDailySteps(){const el=document.getElementById('dailySteps');el.innerHTML='';for(let i=0;i<dy.totalSteps;i++){const d=document.createElement('div');d.className='step-dot'+(i===dy.step?' active':(i<dy.step?' done':''));el.appendChild(d)}}
function loadDailyStep(){const wordEmoji=getSpellingWordEmoji();renderDailySteps();const c=document.getElementById('dailyContent');if(dy.step===0){const w=dy.spellWord;c.innerHTML='<div class="daily-box"><h3>1. Spell the word</h3><div id="dailyPic" style="text-align:center;font-size:3rem;margin:12px 0;">'+(wordEmoji[w.w]&&EMOJI_SVG[wordEmoji[w.w]]?EMOJI_SVG[wordEmoji[w.w]]:'?')+'</div><p style="text-align:center;color:#636e72;font-style:italic;">'+w.h+'</p><input type="text" id="dSpell" class="daily-input" autocomplete="off" autocapitalize="off" placeholder="Type the word..."><button class="daily-submit ds-purple" onclick="checkDSpell()">Check</button></div>';setTimeout(()=>document.getElementById('dSpell').focus(),100)}else if(dy.step===1){c.innerHTML='<div class="daily-box"><h3>2. Solve the sum</h3><div style="text-align:center;font-family:Fredoka One,Comic Sans MS,cursive;font-size:2.2rem;margin:16px 0;">'+dy.mathQ.text+'</div><input type="number" id="dMath" class="daily-input" placeholder="?"><button class="daily-submit ds-blue" onclick="checkDMath()">Check</button></div>';setTimeout(()=>document.getElementById('dMath').focus(),100)}else if(dy.step===2){let h='<div class="daily-box"><h3>3. Reading Question</h3><p style="font-size:0.8rem;color:#b2bec3;margin-bottom:8px;">From: '+dy.readQ.story+'</p><div class="q-text">'+dy.readQ.q.q+'</div>';dy.readQ.q.a.forEach((a,i)=>{h+='<button class="ans-btn" onclick="checkDRead(this,'+i+','+dy.readQ.q.c+')">'+a+'</button>'});h+='</div>';c.innerHTML=h}else if(dy.step===3){const q=dy.bondsQ;let display;if(q.format==='C'){display='<div class="bar-model" style="max-width:260px"><div class="bar-top">'+q.target+'</div><div class="bar-bottom"><div class="bar-part'+(q.left==='?'?' bar-blank':'')+'">'+q.left+'</div><div class="bar-part'+(q.right==='?'?' bar-blank':'')+'">'+q.right+'</div></div></div>'}else{display='<div style="font-family:Fredoka One,Comic Sans MS,cursive;font-size:1.8rem;text-align:center;margin:12px 0">'+q.display+'</div>'}c.innerHTML='<div class="daily-box"><h3>4. Number Bond</h3>'+display+'<input type="number" id="dBonds" class="daily-input" placeholder="?"><button class="daily-submit" style="background:linear-gradient(135deg,#11998e,#38ef7d);box-shadow:0 4px 0 #0e7a6e" onclick="checkDBonds()">Check</button></div>';setTimeout(()=>document.getElementById('dBonds').focus(),100)}else if(dy.step===4){c.innerHTML='<div class="daily-box"><h3>5. Bonus Challenge</h3><div style="text-align:center;font-family:Fredoka One,Comic Sans MS,cursive;font-size:2.2rem;margin:16px 0;">'+dy.bonusQ.text+'</div><input type="number" id="dBonus" class="daily-input" placeholder="?"><button class="daily-submit" style="background:linear-gradient(135deg,#ffd700,#f0932b);box-shadow:0 4px 0 #d4a520;color:#333" onclick="checkDBonus()">Check</button></div>';setTimeout(()=>document.getElementById('dBonus').focus(),100)}}
function checkDSpell(){const v=document.getElementById('dSpell').value.trim().toLowerCase();if(v===dy.spellWord.w){dy.correct++;state.spellingCorrect++;saveState()}dy.step++;loadDailyStep()}
function checkDMath(){const v=parseInt(document.getElementById('dMath').value);if(v===dy.mathQ.answer){dy.correct++;state.mathsCorrect++;saveState()}dy.step++;loadDailyStep()}
function checkDRead(btn,sel,cor){btn.parentElement.querySelectorAll('.ans-btn').forEach((o,i)=>{if(i===cor)o.classList.add('correct-ans');else if(i===sel)o.classList.add('wrong-ans');o.classList.add('disabled')});if(sel===cor)dy.correct++;setTimeout(()=>{dy.step++;loadDailyStep()},1000)}
function checkDBonds(){const v=parseInt(document.getElementById('dBonds').value);if(v===dy.bondsQ.answer){dy.correct++}dy.step++;loadDailyStep()}
function checkDBonus(){const v=parseInt(document.getElementById('dBonus').value);if(v===dy.bonusQ.answer){dy.correct++;addCoins(2)}dy.step++;finishDaily()}
document.addEventListener('keydown',function(e){if(document.getElementById('daily').classList.contains('active')&&e.key==='Enter'){e.preventDefault();if(document.getElementById('dSpell'))checkDSpell();else if(document.getElementById('dMath'))checkDMath();else if(document.getElementById('dBonds'))checkDBonds();else if(document.getElementById('dBonus'))checkDBonus()}});
function finishDaily(){state.dailyCompleted=new Date().toDateString();var prevStreak=storageGetJson('classmates_daily_streak',0);var lastDate=storageGetJson('classmates_daily_last_date',null);var yesterday=new Date(Date.now()-864e5).toDateString();var newStreak=lastDate===yesterday?prevStreak+1:1;storageSetJson('classmates_daily_streak',newStreak);storageSetJson('classmates_daily_last_date',new Date().toDateString());storageSetJson('classmates_daily_last',{score:dy.correct,total:dy.totalSteps,date:new Date().toDateString()});checkAch('daily_1',true);checkAch('first_game',true);checkAch('streak_3',state.streak>=3);checkAch('streak_7',state.streak>=7);var pct=dy.correct/dy.totalSteps;var stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;var subtitle=dy.correct+'/'+dy.totalSteps+' correct';if(newStreak>=3)subtitle+=' · '+newStreak+' day daily streak!';addStars(stars);recordPlay();showResults('#6c5ce7','GO','Daily Challenge Done!',subtitle,stars,dy.correct,dy.totalSteps,()=>{showScreen('daily');initDaily()},null)}

// ==================== SPEED MATHS ====================
let spd={level:1,timer:null,timeLeft:60,score:0,attempted:0,answer:'',question:null,sessionBest:{1:0,2:0,3:0},ops:{'+':{ c:0,t:0},'-':{c:0,t:0},'\u00D7':{c:0,t:0},'\u00F7':{c:0,t:0}}};

function startSpeed(lv){spd.level=lv;spd.timeLeft=60;spd.score=0;spd.attempted=0;spd.answer='';spd.combo=0;spd.maxCombo=0;spd.ops={'+':{ c:0,t:0},'-':{c:0,t:0},'\u00D7':{c:0,t:0},'\u00F7':{c:0,t:0}};var allTimeBest=storageGetJson('classmates_speed_best_'+lv,0);hide('speedLevelSelect');show('speedGame');renderNumpad('speedNumpad',speedPress);loadSpeedQ();document.getElementById('speedTimer').textContent='60';document.getElementById('speedTimer').className='speed-timer normal';document.getElementById('speedScore').textContent='0';var comboEl=document.getElementById('speedCombo');if(comboEl)comboEl.textContent=allTimeBest?'Best: '+allTimeBest+' — go!':'Set your record!';spd.timer=setInterval(speedTick,1000)}

function speedTick(){spd.timeLeft--;const el=document.getElementById('speedTimer');el.textContent=spd.timeLeft;if(spd.timeLeft<=5){el.className='speed-timer red'}else if(spd.timeLeft<=15){el.className='speed-timer amber'}else{el.className='speed-timer normal'}if(spd.timeLeft<=0){clearInterval(spd.timer);spd.timer=null;finishSpeed()}}

function loadSpeedQ(){spd.question=getMathQuestionGenerator()(spd.level);spd.answer='';document.getElementById('speedQ').textContent=spd.question.text;const ans=document.getElementById('speedAns');ans.textContent='_';ans.className='speed-ans normal'}

function speedPress(v){if(!spd.timer)return;if(v==='C'){spd.answer=''}else if(v==='enter'){checkSpeedAns();return}else{if(spd.answer.length<4)spd.answer+=v}document.getElementById('speedAns').textContent=spd.answer||'_'}

function checkSpeedAns(){if(!spd.answer)return;var ok=parseInt(spd.answer)===spd.question.answer;var op=spd.question.text.match(/[+\-\u00D7\u00F7]/);var opKey=op?op[0]:'+';if(spd.ops[opKey])spd.ops[opKey].t++;spd.attempted++;if(ok){spd.combo=(spd.combo||0)+1;spd.maxCombo=Math.max(spd.maxCombo||0,spd.combo);var bonus=spd.combo>=5?3:spd.combo>=3?2:1;spd.score+=bonus;if(spd.ops[opKey])spd.ops[opKey].c++;var ans=document.getElementById('speedAns');ans.className='speed-ans flash-correct';sfxClick();var comboEl=document.getElementById('speedCombo');if(comboEl){if(spd.combo>=5)comboEl.textContent='x3 COMBO! \u{1F525}';else if(spd.combo>=3)comboEl.textContent='x2 combo!';else comboEl.textContent=''}setTimeout(function(){loadSpeedQ()},100)}else{spd.combo=0;var ans2=document.getElementById('speedAns');ans2.className='speed-ans flash-wrong';sfxWrong();var comboEl2=document.getElementById('speedCombo');if(comboEl2)comboEl2.textContent='';setTimeout(function(){loadSpeedQ()},200)}document.getElementById('speedScore').textContent=spd.score}

function endSpeed(){if(spd.timer){clearInterval(spd.timer);spd.timer=null}show('speedLevelSelect');hide('speedGame')}

function finishSpeed(){show('speedLevelSelect');hide('speedGame');var lv=spd.level;var allTimeBest=storageGetJson('classmates_speed_best_'+lv,0);var isNewBest=spd.score>allTimeBest;if(isNewBest)storageSetJson('classmates_speed_best_'+lv,spd.score);if(spd.score>spd.sessionBest[lv])spd.sessionBest[lv]=spd.score;checkAch('first_game',true);checkAch('first_speed',true);checkAch('math_10',state.mathsCorrect+spd.score>=10);state.mathsCorrect+=spd.score;saveState();var thresholds={1:15,2:10,3:7};var t=thresholds[lv];var stars=spd.score>=t*1.5?3:spd.score>=t?2:spd.score>=Math.floor(t/2)?1:0;addStars(stars);recordPlay();var subtitle='Level '+lv+' — '+spd.score+' points';if(isNewBest&&allTimeBest>0)subtitle+=' \u{1F3C6} NEW RECORD! (was '+allTimeBest+')';else if(isNewBest)subtitle+=' \u{1F3C6} New record!';showResults('#0984e3','60s','Speed Maths!',subtitle,stars,spd.score,spd.attempted,function(){showScreen('speed')},null);var extra=document.getElementById('missedWords');var h='';if(isNewBest){h+='<div style="margin:12px auto;text-align:center;background:#e8fff5;border:2px solid #00b894;border-radius:12px;padding:10px;max-width:320px;"><strong style="color:#00b894;">New All-Time Best: '+spd.score+'</strong></div>'}if(spd.maxCombo>=3){h+='<div style="margin:8px auto;text-align:center;font-size:0.85rem;color:#6c5ce7;font-weight:700">Best combo: x'+(spd.maxCombo>=5?'3':'2')+' ('+spd.maxCombo+' in a row)</div>'}h+='<div class="op-breakdown">';var opNames={'+':'Addition','-':'Subtraction','\u00D7':'Multiplication','\u00F7':'Division'};Object.keys(spd.ops).forEach(function(op){var o=spd.ops[op];if(o.t>0){var pct=Math.round(o.c/o.t*100);var cls=pct>=80?'good':pct>=50?'ok':'bad';h+='<div class="op-row '+cls+'"><span>'+opNames[op]+'</span><span>'+o.c+'/'+o.t+' ('+pct+'%)</span></div>'}});h+='</div>';extra.innerHTML=h}

// Keyboard support for speed maths
document.addEventListener('keydown',function(e){if(document.getElementById('speed').classList.contains('active')&&document.getElementById('speedGame').style.display!=='none'){if(/^[0-9]$/.test(e.key))speedPress(e.key);else if(e.key==='Enter')speedPress('enter');else if(e.key==='Backspace'||e.key==='Delete')speedPress('C')}});

