document.addEventListener('keydown',function(e){if(document.getElementById('wordprob').classList.contains('active')&&document.getElementById('wpGame').style.display!=='none'){if(/^[0-9]$/.test(e.key))wpPress(e.key);else if(e.key==='Enter')wpPress('enter');else if(e.key==='Backspace'||e.key==='Delete')wpPress('C')}});

// ==================== FRACTIONS ====================
let frac={level:1,idx:0,total:10,correct:0};

function drawFracBar(total,shaded){let h='<div class="frac-bar">';for(let i=0;i<total;i++){h+='<div class="frac-part '+(i<shaded?'shaded':'unshaded')+'"></div>'}h+='</div>';return h}

function fracStr(n,d){if(n===1&&d===2)return'\u00BD';if(n===1&&d===4)return'\u00BC';if(n===3&&d===4)return'\u00BE';return n+'/'+d}

function genFracQ(lv){const type=rand(0,2);if(lv===1){const denoms=[2,4];const d=denoms[rand(0,1)];const n=rand(1,d-1);if(type<=1){const correct=fracStr(n,d);const wrongs=[fracStr(d-n,d)];if(d===4){wrongs.push(fracStr(n,2));wrongs.push(fracStr(rand(1,3),4))}else{wrongs.push(fracStr(1,4));wrongs.push(fracStr(3,4))}return{prompt:'What fraction is shaded?',visual:drawFracBar(d,n),correct:correct,options:shuffle([correct,...wrongs.filter(w=>w!==correct)]).slice(0,4)}}else{const num=rand(2,10)*2;const ans=num/2;return{prompt:'What is \u00BD of '+num+'?',visual:'',correct:String(ans),options:shuffle([String(ans),String(num),String(ans+2),String(ans-1)].filter(x=>x!=='0')).slice(0,4)}}}else if(lv===2){const denoms=[2,3,4,5,8];const d=denoms[rand(0,4)];const n=rand(1,d-1);if(type===0){const correct=fracStr(n,d);const wrongs=[];for(let i=0;i<3;i++){let wn=rand(1,d-1),wd=denoms[rand(0,4)];const w=fracStr(wn,wd);if(w!==correct&&!wrongs.includes(w))wrongs.push(w)}while(wrongs.length<3)wrongs.push(fracStr(rand(1,5),rand(2,8)));return{prompt:'What fraction is shaded?',visual:drawFracBar(d,n),correct:correct,options:shuffle([correct,...wrongs]).slice(0,4)}}else if(type===1){const a={n:rand(1,3),d:4};const b={n:rand(1,3),d:4};if(a.n===b.n){b.n=a.n<3?a.n+1:a.n-1}const bigger=a.n>b.n?fracStr(a.n,a.d):fracStr(b.n,b.d);const opts=[fracStr(a.n,a.d),fracStr(b.n,b.d)];return{prompt:'Which fraction is bigger?<br>'+fracStr(a.n,a.d)+' or '+fracStr(b.n,b.d),visual:drawFracBar(4,a.n)+'<div style="height:8px"></div>'+drawFracBar(4,b.n),correct:bigger,options:shuffle(opts)}}else{const num=rand(2,8)*5;const ans=num/5;return{prompt:'What is 1/5 of '+num+'?',visual:'',correct:String(ans),options:shuffle([String(ans),String(num),String(ans*2),String(ans+3)]).slice(0,4)}}}else{const type3=rand(0,2);if(type3===0){return{prompt:'Which fractions are equivalent?<br>1/2 = ?/4',visual:drawFracBar(2,1)+'<div style="height:8px"></div>'+drawFracBar(4,2),correct:'2/4',options:shuffle(['2/4','1/4','3/4','4/4'])}}else if(type3===1){const num=rand(3,20)*4;const frac_of=num/4;return{prompt:'What is \u00BC of '+num+'?',visual:'',correct:String(frac_of),options:shuffle([String(frac_of),String(num/2),String(frac_of+2),String(frac_of-1)].filter(x=>Number(x)>0)).slice(0,4)}}else{const pairs=[{f:'1/2',d:'0.5'},{f:'1/4',d:'0.25'},{f:'3/4',d:'0.75'},{f:'1/10',d:'0.1'}];const p=pairs[rand(0,3)];return{prompt:'What is '+p.f+' as a decimal?',visual:drawFracBar(p.f==='1/2'?2:p.f==='1/10'?10:4,p.f==='3/4'?3:1),correct:p.d,options:shuffle([p.d,...pairs.filter(x=>x.d!==p.d).map(x=>x.d)]).slice(0,4)}}}}

function startFrac(lv){frac.level=lv;frac.idx=0;frac.correct=0;hide('fracLevelSelect');show('fracGame');loadFracQ()}
function loadFracQ(){const q=genFracQ(frac.level);frac.question=q;document.getElementById('fracProgress').style.width=(frac.idx/frac.total*100)+'%';document.getElementById('fracProgressText').textContent='Question '+(frac.idx+1)+' of '+frac.total;document.getElementById('fracDisplay').innerHTML=(q.visual?'<div class="frac-shape">'+q.visual+'</div>':'')+'<div class="ph-sound" style="background:#fff5f7;border-color:#ee9ca7;color:#c0392b;font-size:1rem">'+q.prompt+'</div>';const opts=document.getElementById('fracOpts');opts.innerHTML='';q.options.forEach(o=>{const b=document.createElement('button');b.className='ph-opt';b.textContent=o;b.onclick=()=>selectFracAns(b,o===q.correct,q.correct);opts.appendChild(b)})}
function selectFracAns(btn,correct,rightAnswer){document.querySelectorAll('#fracOpts .ph-opt').forEach(o=>{o.classList.add('ph-disabled');if(o.textContent===rightAnswer)o.classList.add('ph-correct')});if(correct){frac.correct++;btn.classList.add('ph-correct')}else{btn.classList.add('ph-wrong')}setTimeout(()=>{frac.idx++;if(frac.idx>=frac.total)finishFrac();else loadFracQ()},correct?500:1200)}
function finishFrac(){show('fracLevelSelect');hide('fracGame');const pct=frac.correct/frac.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;checkAch('first_game',true);checkAch('first_fractions',true);if(pct>=0.8)adaptiveCorrect('fractions');else if(pct<0.4)adaptiveWrong('fractions');addStars(stars);recordPlay();showResults('#c0392b','\u00BD','Fractions Done!','Level '+frac.level,stars,frac.correct,frac.total,()=>{showScreen('fractions')},null)}

// ==================== MONEY ====================
const COINS=[{v:1,label:'1p',cls:'coin-1p'},{v:2,label:'2p',cls:'coin-2p'},{v:5,label:'5p',cls:'coin-5p'},{v:10,label:'10p',cls:'coin-10p'},{v:20,label:'20p',cls:'coin-20p'},{v:50,label:'50p',cls:'coin-50p'},{v:100,label:'\u00A31',cls:'coin-100'},{v:200,label:'\u00A32',cls:'coin-200'}];

let money={level:1,idx:0,total:10,correct:0,streak:0};

function renderCoins(vals){let h='<div class="coin-display">';vals.forEach(v=>{const c=COINS.find(x=>x.v===v);if(c)h+='<div class="coin '+c.cls+'">'+c.label+'</div>'});h+='</div>';return h}

function formatMoney(p){if(p>=100)return'\u00A3'+(p/100).toFixed(2);return p+'p'}

function genMoneyQ(lv){const type=rand(0,1);if(type===0){let available,target;if(lv===1){available=[1,1,2,2,5,5,10];target=rand(3,20)}else if(lv===2){available=[1,2,5,10,10,20,20,50];target=rand(15,100)}else{available=[10,20,20,50,50,100,100,200];target=rand(50,500)}const picked=[];let sum=0;const pool=[...available];shuffle(pool);for(const c of pool){if(sum+c<=target+10&&picked.length<6){picked.push(c);sum+=c}}if(picked.length<2){picked.push(pool[0]);sum+=pool[0]}const correct=formatMoney(sum);const wrongs=[];while(wrongs.length<3){const w=formatMoney(sum+rand(-10,10)*(lv===3?10:1));if(w!==correct&&!wrongs.includes(w)&&!w.startsWith('-'))wrongs.push(w)}return{prompt:'How much money is shown?',coins:picked,correct:correct,options:shuffle([correct,...wrongs])}}else{let from;if(lv===1)from=20;else if(lv===2)from=100;else from=rand(2,5)*100;const spent=rand(Math.floor(from*0.2),Math.floor(from*0.7));const change=from-spent;const correct=formatMoney(change);const wrongs=[];while(wrongs.length<3){const w=formatMoney(change+rand(-15,15)*(lv===3?5:1));if(w!==correct&&!wrongs.includes(w)&&!w.startsWith('-')&&w!=='0p')wrongs.push(w)}return{prompt:'You spend '+formatMoney(spent)+'. How much change from '+formatMoney(from)+'?',coins:null,correct:correct,options:shuffle([correct,...wrongs])}}}

function startMoney(lv){money.level=lv;money.idx=0;money.correct=0;money.streak=0;hide('moneyLevelSelect');show('moneyGame');loadMoneyQ()}
function loadMoneyQ(){const q=genMoneyQ(money.level);money.question=q;document.getElementById('moneyProgress').style.width=(money.idx/money.total*100)+'%';document.getElementById('moneyProgressText').textContent='Question '+(money.idx+1)+' of '+money.total;document.getElementById('moneyDisplay').innerHTML=(q.coins?renderCoins(q.coins):'')+'<div class="ph-sound" style="background:#f0fff5;border-color:#2ecc71;color:#1a5276;font-size:1rem">'+q.prompt+'</div>';const opts=document.getElementById('moneyOpts');opts.innerHTML='';q.options.forEach(o=>{const b=document.createElement('button');b.className='ph-opt';b.textContent=o;b.onclick=()=>selectMoneyAns(b,o===q.correct,q.correct);opts.appendChild(b)})}
function selectMoneyAns(btn,correct,rightAnswer){document.querySelectorAll('#moneyOpts .ph-opt').forEach(function(o){o.classList.add('ph-disabled');if(o.textContent===rightAnswer)o.classList.add('ph-correct')});if(correct){money.correct++;money.streak=(money.streak||0)+1;btn.classList.add('ph-correct');if(money.streak>=3)btn.textContent=rightAnswer+' \u2714 '+money.streak+'!'}else{money.streak=0;btn.classList.add('ph-wrong')}setTimeout(function(){money.idx++;if(money.idx>=money.total)finishMoney();else loadMoneyQ()},correct?500:1200)}
function finishMoney(){show('moneyLevelSelect');hide('moneyGame');const pct=money.correct/money.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;checkAch('first_game',true);checkAch('first_money',true);if(pct>=0.8)adaptiveCorrect('money');else if(pct<0.4)adaptiveWrong('money');addStars(stars);recordPlay();showResults('#1a5276','\u00A3p','Money Done!','Level '+money.level,stars,money.correct,money.total,()=>{showScreen('money')},null)}

// ==================== TELLING TIME ====================
let ttime={level:1,idx:0,total:10,correct:0,streak:0};

function drawClock(hour,minute){const r=78;let html='<div class="clock-face">';for(let i=1;i<=12;i++){const angle=(i*30-90)*Math.PI/180;const x=90+r*0.78*Math.cos(angle);const y=90+r*0.78*Math.sin(angle);html+='<div class="clock-num" style="left:'+x+'px;top:'+y+'px">'+i+'</div>'}for(let i=0;i<12;i++){const angle=(i*30)*Math.PI/180;const x=90+r*0.9*Math.cos(angle);const y=90+r*0.9*Math.sin(angle);html+='<div class="clock-dot" style="left:'+(x-2)+'px;top:'+(y-2)+'px"></div>'}const hAngle=(hour%12+minute/60)*30-90;const mAngle=minute*6-90;html+='<div class="clock-hand clock-hour" style="transform:rotate('+hAngle+'deg)"></div>';html+='<div class="clock-hand clock-minute" style="transform:rotate('+mAngle+'deg)"></div>';html+='<div class="clock-center"></div></div>';return html}

function timeToWords(h,m){const hours=['twelve','one','two','three','four','five','six','seven','eight','nine','ten','eleven'];if(m===0)return hours[h%12]+" o'clock";if(m===15)return'quarter past '+hours[h%12];if(m===30)return'half past '+hours[h%12];if(m===45)return'quarter to '+hours[(h+1)%12];if(m<30)return m+' past '+hours[h%12];return(60-m)+' to '+hours[(h+1)%12]}

function genTTimeQ(lv){const h=rand(1,12);let m;if(lv===1){m=[0,30][rand(0,1)]}else if(lv===2){m=[0,15,30,45][rand(0,3)]}else{m=rand(0,11)*5}const correct=timeToWords(h,m);const wrongs=[];while(wrongs.length<3){let wh=rand(1,12),wm;if(lv===1)wm=[0,30][rand(0,1)];else if(lv===2)wm=[0,15,30,45][rand(0,3)];else wm=rand(0,11)*5;const w=timeToWords(wh,wm);if(w!==correct&&!wrongs.includes(w))wrongs.push(w)}return{hour:h,minute:m,correct:correct,options:shuffle([correct,...wrongs])}}

function startTTime(lv){ttime.level=lv;ttime.idx=0;ttime.correct=0;ttime.streak=0;hide('ttimeLevelSelect');show('ttimeGame');loadTTimeQ()}
function loadTTimeQ(){const q=genTTimeQ(ttime.level);ttime.question=q;document.getElementById('ttimeProgress').style.width=(ttime.idx/ttime.total*100)+'%';document.getElementById('ttimeProgressText').textContent='Question '+(ttime.idx+1)+' of '+ttime.total;document.getElementById('clockDisplay').innerHTML=drawClock(q.hour,q.minute);const opts=document.getElementById('ttimeOpts');opts.innerHTML='';q.options.forEach(o=>{const b=document.createElement('button');b.className='ph-opt';b.textContent=o;b.onclick=()=>selectTTimeAns(b,o===q.correct,q.correct);opts.appendChild(b)})}
function selectTTimeAns(btn,correct,rightAnswer){document.querySelectorAll('#ttimeOpts .ph-opt').forEach(function(o){o.classList.add('ph-disabled');if(o.textContent===rightAnswer)o.classList.add('ph-correct')});if(correct){ttime.correct++;ttime.streak=(ttime.streak||0)+1;btn.classList.add('ph-correct');if(ttime.streak>=3)btn.textContent=rightAnswer+' \u2714 '+ttime.streak+'!'}else{ttime.streak=0;btn.classList.add('ph-wrong')}setTimeout(function(){ttime.idx++;if(ttime.idx>=ttime.total)finishTTime();else loadTTimeQ()},correct?500:1200)}
function finishTTime(){show('ttimeLevelSelect');hide('ttimeGame');const pct=ttime.correct/ttime.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;checkAch('first_game',true);checkAch('first_time',true);if(pct>=0.8)adaptiveCorrect('time');else if(pct<0.4)adaptiveWrong('time');addStars(stars);recordPlay();showResults('#2c3e50','3:00','Telling Time Done!','Level '+ttime.level,stars,ttime.correct,ttime.total,()=>{showScreen('telltime')},null)}

// ==================== PLACE VALUE ====================
let pv={level:1,idx:0,total:10,correct:0,question:null,streak:0};

function renderBlocks(h,t,o){let html='<div class="pv-blocks">';if(h>0){html+='<div class="pv-col"><div class="pv-col-label">Hundreds</div><div class="pv-block-row">';for(let i=0;i<h;i++)html+='<div class="pv-block pv-h"></div>';html+='</div></div>'}if(t>0||h>0){html+='<div class="pv-col"><div class="pv-col-label">Tens</div><div class="pv-block-row">';for(let i=0;i<t;i++)html+='<div class="pv-block pv-t"></div>';html+='</div></div>'}html+='<div class="pv-col"><div class="pv-col-label">Ones</div><div class="pv-block-row">';for(let i=0;i<o;i++)html+='<div class="pv-block pv-o"></div>';html+='</div></div></div>';return html}

function genPVQ(lv){const type=rand(0,2);if(lv===1){const num=rand(11,99);const tens=Math.floor(num/10);const ones=num%10;if(type===0){return{prompt:'What is the tens digit in '+num+'?',answer:tens,options:shuffle([tens,ones,tens+1,rand(1,9)].filter((v,i,a)=>a.indexOf(v)===i)).slice(0,4),blocks:renderBlocks(0,tens,ones)}}else if(type===1){const t=rand(1,9);const o=rand(0,9);return{prompt:t+' tens and '+o+' ones = ?',answer:t*10+o,options:shuffle([t*10+o,t+o,t*10+o+10,t*10+o-10].filter(x=>x>=0)).slice(0,4),blocks:renderBlocks(0,t,o)}}else{const n=rand(11,89);const add=10;return{prompt:'What is 10 more than '+n+'?',answer:n+add,options:shuffle([n+add,n+1,n-10,n+add+10].filter(x=>x>0)).slice(0,4),blocks:''}}}else if(lv===2){const num=rand(100,999);const h=Math.floor(num/100);const t=Math.floor((num%100)/10);const o=num%10;if(type===0){return{prompt:'What is the hundreds digit in '+num+'?',answer:h,options:shuffle([h,t,o,h+1].filter((v,i,a)=>a.indexOf(v)===i)).slice(0,4),blocks:renderBlocks(h,t,o)}}else if(type===1){const hv=rand(1,9);const tv=rand(0,9);const ov=rand(0,9);const ans=hv*100+tv*10+ov;return{prompt:hv+' hundreds, '+tv+' tens, '+ov+' ones = ?',answer:ans,options:shuffle([ans,ans+100,ans-10,hv*10+tv+ov].filter(x=>x>0&&x!==ans).slice(0,3).concat([ans])),blocks:renderBlocks(hv,tv,ov)}}else{const n=rand(100,899);return{prompt:'What is 100 more than '+n+'?',answer:n+100,options:shuffle([n+100,n+10,n+1,n-100].filter(x=>x>0)).slice(0,4),blocks:''}}}else{const num=rand(1000,9999);const th=Math.floor(num/1000);const h=Math.floor((num%1000)/100);const t=Math.floor((num%100)/10);const o=num%10;if(type===0){return{prompt:'What is the value of the '+th+' in '+num+'?',answer:th*1000,options:shuffle([th*1000,th*100,th*10,th]).slice(0,4),blocks:''}}else if(type===1){return{prompt:'What is 1000 more than '+num+'?',answer:num+1000,options:shuffle([num+1000,num+100,num+10,num-1000].filter(x=>x>0)).slice(0,4),blocks:''}}else{const n=rand(10,99);const dec=rand(1,9);const val=n+dec/10;return{prompt:'What is the value of '+dec+' in '+val.toFixed(1)+'?',answer:dec,options:shuffle([dec,dec*10,n,dec/10].filter((v,i,a)=>a.indexOf(v)===i)).slice(0,4),blocks:''}}}}

function startPV(lv){pv.level=lv;pv.idx=0;pv.correct=0;hide('pvLevelSelect');show('pvGame');loadPVQ()}
function loadPVQ(){pv.question=genPVQ(pv.level);document.getElementById('pvProgress').style.width=(pv.idx/pv.total*100)+'%';document.getElementById('pvProgressText').textContent='Question '+(pv.idx+1)+' of '+pv.total;const d=document.getElementById('pvDisplay');d.innerHTML=(pv.question.blocks||'')+'<div class="ph-sound" style="background:#fff5f0;border-color:#eea849;color:#f46b45;font-size:1.1rem">'+pv.question.prompt+'</div>';const opts=document.getElementById('pvOpts');opts.innerHTML='';pv.question.options.forEach(o=>{const b=document.createElement('button');b.className='ph-opt';b.textContent=o;b.onclick=()=>selectPVAns(b,o===pv.question.answer,pv.question.answer);opts.appendChild(b)})}
function selectPVAns(btn,correct,rightAnswer){document.querySelectorAll('#pvOpts .ph-opt').forEach(function(o){o.classList.add('ph-disabled');if(Number(o.textContent)===rightAnswer)o.classList.add('ph-correct')});if(correct){pv.correct++;pv.streak=(pv.streak||0)+1;btn.classList.add('ph-correct');if(pv.streak>=3)btn.textContent=rightAnswer+' \u2714 '+pv.streak+'!'}else{pv.streak=0;btn.classList.add('ph-wrong')}setTimeout(function(){pv.idx++;if(pv.idx>=pv.total)finishPV();else loadPVQ()},correct?500:1200)}
function finishPV(){show('pvLevelSelect');hide('pvGame');const pct=pv.correct/pv.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;checkAch('first_game',true);checkAch('first_placeval',true);if(pct>=0.8)adaptiveCorrect('placeval');else if(pct<0.4)adaptiveWrong('placeval');addStars(stars);recordPlay();showResults('#f46b45','HTO','Place Value Done!','Level '+pv.level,stars,pv.correct,pv.total,()=>{showScreen('placeval')},null)}

// ==================== MISSING NUMBER ====================
let mn={level:1,idx:0,total:10,correct:0,answer:'',question:null,streak:0};

function genMNQ(lv){const type=Math.random()<0.7?'equation':'sequence';if(type==='sequence'){let start,step;if(lv===1){step=rand(1,2);start=rand(1,5)}else if(lv===2){step=rand(2,5);start=rand(1,10)}else{step=rand(5,10)*rand(1,3);start=rand(1,20)}const seq=[];for(let i=0;i<5;i++)seq.push(start+step*i);const miss=rand(1,3);const ans=seq[miss];seq[miss]='?';return{text:seq.join(', '),answer:ans}}let a,b,op,ans,display;if(lv===1){const r=Math.random();if(r<0.5){a=rand(1,9);ans=rand(1,10-a);op='+';display=a+' + ? = '+(a+ans)}else{a=rand(3,10);ans=rand(1,a-1);op='-';display=a+' - ? = '+(a-ans)}}else if(lv===2){const r=Math.random();if(r<0.3){ans=rand(1,15);b=rand(1,20-ans);op='+';display='? + '+b+' = '+(ans+b)}else if(r<0.6){a=rand(5,20);ans=rand(1,a);op='-';display=a+' - ? = '+(a-ans)}else{a=rand(2,5);ans=rand(2,5);op='*';display=a+' \u00D7 ? = '+(a*ans)}}else{const r=Math.random();if(r<0.25){ans=rand(10,80);b=rand(5,100-ans);display='? + '+b+' = '+(ans+b)}else if(r<0.5){a=rand(20,100);ans=rand(5,a);display=a+' - ? = '+(a-ans)}else if(r<0.75){a=rand(2,12);ans=rand(2,12);display=a+' \u00D7 ? = '+(a*ans)}else{a=rand(2,12);b=rand(2,12);ans=b;display=(a*b)+' \u00F7 ? = '+a}}return{text:display,answer:ans}}

function startMN(lv){mn.level=lv;mn.idx=0;mn.correct=0;mn.answer='';mn.streak=0;hide('mnLevelSelect');show('mnGame');renderNumpad('mnNumpad',mnPress);loadMNQ()}
function loadMNQ(){mn.question=genMNQ(mn.level);mn.answer='';document.getElementById('mnQuestion').textContent=mn.question.text;document.getElementById('mnAnswer').textContent='_';document.getElementById('mnProgress').style.width=(mn.idx/mn.total*100)+'%';document.getElementById('mnProgressText').textContent='Question '+(mn.idx+1)+' of '+mn.total;document.getElementById('mnFeedback').classList.remove('show')}
function mnPress(v){if(v==='C')mn.answer='';else if(v==='enter'){checkMNAns();return}else{if(mn.answer.length<4)mn.answer+=v}document.getElementById('mnAnswer').textContent=mn.answer||'_'}
function checkMNAns(){if(!mn.answer)return;var ok=parseInt(mn.answer)===mn.question.answer;var fb=document.getElementById('mnFeedback');var fbc=document.getElementById('mnFeedbackContent');var encouragements=['Great!','Nice!','Yes!','Smart!','Correct!'];if(ok){mn.correct++;mn.streak=(mn.streak||0)+1;var word=encouragements[Math.floor(Math.random()*encouragements.length)];var streakText=mn.streak>=3?' Streak: '+mn.streak+'!':'';fbc.innerHTML='<div class="fb-correct"><div class="fb-icon" style="background:linear-gradient(135deg,#134e5e,#71b280)">'+word+'</div><div class="fb-text" style="color:#00b894">'+word+streakText+'</div></div>'}else{mn.streak=0;fbc.innerHTML='<div class="fb-wrong"><div class="fb-icon">'+mn.question.answer+'</div><div class="fb-text">The answer was '+mn.question.answer+'</div></div>'}fb.classList.add('show');setTimeout(()=>{fb.classList.remove('show');mn.idx++;if(mn.idx>=mn.total)finishMN();else loadMNQ()},ok?600:1200)}
function finishMN(){show('mnLevelSelect');hide('mnGame');const pct=mn.correct/mn.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;checkAch('first_game',true);checkAch('first_missnum',true);state.mathsCorrect+=mn.correct;saveState();if(pct>=0.8)adaptiveCorrect('missnum');else if(pct<0.4)adaptiveWrong('missnum');addStars(stars);recordPlay();showResults('#134e5e','?=','Missing Number Done!','Level '+mn.level,stars,mn.correct,mn.total,()=>{showScreen('missnum')},null)}

document.addEventListener('keydown',function(e){if(document.getElementById('missnum').classList.contains('active')&&document.getElementById('mnGame').style.display!=='none'){if(/^[0-9]$/.test(e.key))mnPress(e.key);else if(e.key==='Enter')mnPress('enter');else if(e.key==='Backspace'||e.key==='Delete')mnPress('C')}});

