let voc={level:1,questions:[],idx:0,total:10,correct:0};

function startVocab(lv){voc.level=lv;const pool=[...VOCAB_DATA[lv]];shuffle(pool);voc.questions=[];pool.slice(0,10).forEach(item=>{const type=Math.random()<0.5?'def2word':'word2def';if(type==='def2word'){const wrongs=pool.filter(x=>x.w!==item.w).slice(0,3).map(x=>x.w);voc.questions.push({type:'def2word',prompt:item.d,correct:item.w,options:shuffle([item.w,...wrongs])})}else{voc.questions.push({type:'word2def',prompt:item.w,correct:item.d,options:shuffle([item.d,...item.wrong])})}});voc.idx=0;voc.correct=0;hide('vocabLevelSelect');show('vocabGame');loadVocQ()}

function loadVocQ(){const q=voc.questions[voc.idx];document.getElementById('vocProgress').style.width=(voc.idx/voc.total*100)+'%';document.getElementById('vocProgressText').textContent='Question '+(voc.idx+1)+' of '+voc.total;const prompt=document.getElementById('vocPrompt');prompt.textContent=q.type==='word2def'?'What does "'+q.prompt+'" mean?':'Which word means: "'+q.prompt+'"?';const d=document.getElementById('vocOpts');d.innerHTML='';q.options.forEach(o=>{const b=document.createElement('button');b.className='ph-opt';b.textContent=o;b.style.textAlign='left';b.onclick=()=>selectVocAns(b,o===q.correct,q.correct);d.appendChild(b)})}

function selectVocAns(btn,correct,rightAnswer){document.querySelectorAll('#vocOpts .ph-opt').forEach(o=>{o.classList.add('ph-disabled');if(o.textContent===rightAnswer)o.classList.add('ph-correct')});if(correct){voc.correct++;btn.classList.add('ph-correct')}else{btn.classList.add('ph-wrong')}setTimeout(()=>{voc.idx++;if(voc.idx>=voc.total)finishVocab();else loadVocQ()},correct?500:1500)}

function finishVocab(){show('vocabLevelSelect');hide('vocabGame');const pct=voc.correct/voc.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;checkAch('first_game',true);checkAch('first_vocab',true);if(pct>=0.8)adaptiveCorrect('vocab');else if(pct<0.4)adaptiveWrong('vocab');addStars(stars);recordPlay();showResults('#4776e6','A-Z','Vocabulary Done!','Level '+voc.level,stars,voc.correct,voc.total,()=>{showScreen('vocab')},null)}

