function loadSentQ(){const s=sent.sentences[sent.idx];const words=s.split(' ');sent.pool=[...words];shuffle(sent.pool);sent.ans=[];sent.correctSentence=s;document.getElementById('sentProgress').style.width=(sent.idx/sent.total*100)+'%';document.getElementById('sentProgressText').textContent='Sentence '+(sent.idx+1)+' of '+sent.total;document.getElementById('sentFeedback').innerHTML='';document.getElementById('sentCheck').style.display='block';renderSent()}

