function checkSentAns(){if(sent.pool.length>0)return;const attempt=sent.ans.join(' ');const correct=attempt===sent.correctSentence;if(correct){sent.correct++;document.getElementById('sentFeedback').innerHTML='<div class="sent-correct-display">Correct!</div>'}else{document.getElementById('sentFeedback').innerHTML='<div class="sent-correct-display" style="background:#fff0ed;border-color:#e17055;color:#e17055">'+sent.correctSentence+'</div>'}document.getElementById('sentCheck').style.display='none';setTimeout(()=>{sent.idx++;if(sent.idx>=sent.total)finishSent();else loadSentQ()},correct?800:2000)}

