let wf={level:1,questions:[],idx:0,total:10,correct:0,missed:[]};

function startWF(lv){wf.level=lv;wf.idx=0;wf.correct=0;wf.missed=[];const groups=[...WORDFAM_DATA[lv]];wf.questions=[];for(let i=0;i<12;i++){const g=groups[i%groups.length];const type=Math.random()<0.5?'which':'suffix';if(type==='which'){const correct=g.words[rand(0,g.words.length-1)];const wrongs=shuffle([...g.wrong]).slice(0,3);wf.questions.push({type:'which',ending:g.ending,correct:correct,options:shuffle([correct,...wrongs])})}else{const word=g.words[rand(0,g.words.length-1)];const stem=word.replace(new RegExp(g.ending.slice(1)+'$'),'');if(stem===word||stem.length<1){const correct=g.words[rand(0,g.words.length-1)];const wrongs=shuffle([...g.wrong]).slice(0,3);wf.questions.push({type:'which',ending:g.ending,correct:correct,options:shuffle([correct,...wrongs])})}else{const wrongEndings=WORDFAM_DATA[lv].filter(x=>x.ending!==g.ending).map(x=>x.ending.slice(1)).slice(0,3);wf.questions.push({type:'suffix',ending:g.ending,word:word,stem:stem,suffix:g.ending.slice(1),options:shuffle([g.ending.slice(1),...wrongEndings])})}}}shuffle(wf.questions);wf.questions=wf.questions.slice(0,10);hide('wfLevelSelect');show('wfGame');loadWFQ()}

function loadWFQ(){const q=wf.questions[wf.idx];document.getElementById('wfProgress').style.width=(wf.idx/wf.total*100)+'%';document.getElementById('wfProgressText').textContent='Question '+(wf.idx+1)+' of '+wf.total;const d=document.getElementById('wfDisplay');if(q.type==='which'){d.innerHTML='<div class="ph-sound" style="background:#f3e6f9;border-color:#c39bd3;color:#8e44ad">Which word belongs to the '+q.ending+' family?</div><div class="ph-options" id="wfOpts"></div>';const opts=document.getElementById('wfOpts');q.options.forEach(o=>{const b=document.createElement('button');b.className='ph-opt';b.textContent=o;b.onclick=()=>selectWFAns(b,o===q.correct,q);opts.appendChild(b)})}else{d.innerHTML='<div class="ph-prompt">Add the correct ending:</div><div class="ph-word-display">'+q.stem+'<span class="ph-blank" style="border-color:#8e44ad;color:#8e44ad">?</span></div><div class="ph-options" id="wfOpts"></div>';const opts=document.getElementById('wfOpts');q.options.forEach(o=>{const b=document.createElement('button');b.className='ph-opt';b.textContent='-'+o;b.onclick=()=>selectWFAns(b,o===q.suffix,q);opts.appendChild(b)})}}

function selectWFAns(btn,correct,q){document.querySelectorAll('#wfOpts .ph-opt').forEach(o=>{o.classList.add('ph-disabled')});if(correct){wf.correct++;btn.classList.add('ph-correct')}else{wf.missed.push(q);btn.classList.add('ph-wrong');document.querySelectorAll('#wfOpts .ph-opt').forEach(o=>{if(o.textContent===q.correct||o.textContent==='-'+q.suffix)o.classList.add('ph-correct')})}setTimeout(()=>{wf.idx++;if(wf.idx>=wf.total)finishWF();else loadWFQ()},correct?500:1200)}

function finishWF(){show('wfLevelSelect');hide('wfGame');const pct=wf.correct/wf.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;checkAch('first_game',true);checkAch('first_wordfam',true);if(pct>=0.8)adaptiveCorrect('wordfam');else if(pct<0.4)adaptiveWrong('wordfam');addStars(stars);recordPlay();showResults('#8e44ad','-ing','Word Families Done!','Level '+wf.level,stars,wf.correct,wf.total,()=>{showScreen('wordfam')},null)}

