let ph={level:1,questions:[],idx:0,total:10,correct:0,missed:[]};

function startPhonics(lv){ph.level=lv;ph.idx=0;ph.correct=0;ph.missed=[];const groups=[...PHONICS_DATA[lv]];shuffle(groups);ph.questions=[];for(let i=0;i<Math.min(10,groups.length*2);i++){const g=groups[i%groups.length];const type=Math.random()<0.5?'identify':'complete';if(type==='identify'){const correct=g.words[rand(0,g.words.length-1)];const wrongs=shuffle([...g.wrong]).slice(0,3);const opts=shuffle([correct,...wrongs]);ph.questions.push({type:'identify',sound:g.sound,correct:correct,options:opts})}else{const word=g.words[rand(0,g.words.length-1)];const gapWord=word.replace(new RegExp(g.sound,'i'),'___');if(gapWord===word){const correct=g.words[rand(0,g.words.length-1)];const wrongs=shuffle([...g.wrong]).slice(0,3);const opts=shuffle([correct,...wrongs]);ph.questions.push({type:'identify',sound:g.sound,correct:correct,options:opts})}else{const wrongSounds=PHONICS_DATA[lv].filter(x=>x.sound!==g.sound).map(x=>x.sound).slice(0,3);const opts=shuffle([g.sound,...wrongSounds]);ph.questions.push({type:'complete',sound:g.sound,word:word,gapWord:gapWord,options:opts})}}}shuffle(ph.questions);ph.questions=ph.questions.slice(0,10);hide('phonicsLevelSelect');show('phonicsGame');loadPhQ()}

function loadPhQ(){const q=ph.questions[ph.idx];document.getElementById('phProgress').style.width=(ph.idx/ph.total*100)+'%';document.getElementById('phProgressText').textContent='Question '+(ph.idx+1)+' of '+ph.total;const d=document.getElementById('phDisplay');if(q.type==='identify'){d.innerHTML='<div class="ph-sound">Which word has the /'+q.sound+'/ sound?</div><div class="ph-options" id="phOpts"></div>';const opts=document.getElementById('phOpts');q.options.forEach((o,i)=>{const b=document.createElement('button');b.className='ph-opt';b.textContent=o;b.onclick=()=>selectPhAns(b,o===q.correct,q);opts.appendChild(b)})}else{d.innerHTML='<div class="ph-prompt">Fill in the missing sound:</div><div class="ph-word-display">'+q.gapWord.replace('___','<span class="ph-blank">?</span>')+'</div><div class="ph-options" id="phOpts"></div>';const opts=document.getElementById('phOpts');q.options.forEach(o=>{const b=document.createElement('button');b.className='ph-opt';b.textContent=o;b.onclick=()=>selectPhAns(b,o===q.sound,q);opts.appendChild(b)})}}

function selectPhAns(btn,correct,q){document.querySelectorAll('#phOpts .ph-opt').forEach((o,i)=>{o.classList.add('ph-disabled');if(o.textContent===q.correct||o.textContent===q.sound)o.classList.add('ph-correct')});if(correct){ph.correct++;sfxCorrect();btn.classList.add('ph-correct')}else{ph.missed.push(q);sfxWrong();btn.classList.add('ph-wrong')}setTimeout(()=>{ph.idx++;if(ph.idx>=ph.total)finishPhonics();else loadPhQ()},correct?500:1200)}

function finishPhonics(){show('phonicsLevelSelect');hide('phonicsGame');const pct=ph.correct/ph.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;checkAch('first_game',true);checkAch('first_phonics',true);if(pct>=0.8)adaptiveCorrect('phonics');else if(pct<0.4)adaptiveWrong('phonics');addStars(stars);recordPlay();showResults('#0abde3','ai','Phonics Done!','Level '+ph.level,stars,ph.correct,ph.total,()=>{showScreen('phonics')},null)}

