let ana={level:1,words:[],idx:0,total:10,correct:0,missed:[],word:'',pool:[],ans:[]};

function startAnagram(lv){ana.level=lv;const p=[...getSpellingWords()[lv]];shuffle(p);ana.words=p.slice(0,ana.total);ana.idx=0;ana.correct=0;ana.missed=[];hide('anagramLevelSelect');show('anagramGame');loadAnaQ()}

function loadAnaQ(){const wordEmoji=getSpellingWordEmoji();const item=ana.words[ana.idx];ana.word=item.w.toLowerCase();const letters=ana.word.split('');ana.pool=[...letters];shuffle(ana.pool);ana.ans=[];document.getElementById('anaProgress').style.width=(ana.idx/ana.total*100)+'%';document.getElementById('anaProgressText').textContent='Word '+(ana.idx+1)+' of '+ana.total;const pic=document.getElementById('anaPic');const eFn=wordEmoji[ana.word];if(eFn&&EMOJI_SVG[eFn]){pic.innerHTML=EMOJI_SVG[eFn];pic.style.display=''}else{pic.textContent='?';pic.style.display=''};document.getElementById('anaHint').textContent=item.h;renderAna()}

function renderAna(){const pool=document.getElementById('anaPool');const ans=document.getElementById('anaAns');pool.innerHTML='';ans.innerHTML='';ana.ans.forEach((ch,i)=>{const t=document.createElement('div');t.className='anagram-tile ans-tile';t.textContent=ch;t.onclick=()=>{ana.pool.push(ana.ans.splice(i,1)[0]);renderAna()};ans.appendChild(t)});for(let i=ana.ans.length;i<ana.word.length;i++){const t=document.createElement('div');t.className='anagram-tile';t.style.background='transparent';t.style.border='3px dashed #f0d0e0';t.style.boxShadow='none';ans.appendChild(t)}ana.pool.forEach((ch,i)=>{const t=document.createElement('div');t.className='anagram-tile pool-tile';t.textContent=ch;t.onclick=()=>{ana.ans.push(ana.pool.splice(i,1)[0]);renderAna();if(ana.ans.length===ana.word.length)checkAnaAns()};pool.appendChild(t)})}

function checkAnaAns(){const attempt=ana.ans.join('');const correct=attempt===ana.word;const tiles=document.querySelectorAll('#anaAns .ans-tile');if(correct)sfxCorrect();else sfxWrong();tiles.forEach(t=>t.className='anagram-tile '+(correct?'correct-tile':'wrong-tile'));if(correct){ana.correct++;state.spellingCorrect++;checkAch('spell_10',state.spellingCorrect>=10);checkAch('spell_50',state.spellingCorrect>=50);saveState();setTimeout(()=>{ana.idx++;if(ana.idx>=ana.total)finishAnagram();else loadAnaQ()},500)}else{ana.missed.push({w:ana.word,h:ana.words[ana.idx].h});document.getElementById('anaHint').textContent='It was: '+ana.word;setTimeout(()=>{ana.idx++;if(ana.idx>=ana.total)finishAnagram();else loadAnaQ()},1500)}}

function finishAnagram(){show('anagramLevelSelect');hide('anagramGame');const pct=ana.correct/ana.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;if(pct===1)checkAch('perfect_spell',true);checkAch('first_game',true);checkAch('first_anagram',true);if(pct>=0.8)adaptiveCorrect('anagram');else if(pct<0.4)adaptiveWrong('anagram');ana.missed.forEach(m=>recordWeak('spelling',m));addStars(stars);recordPlay();showResults('#c44569','ABC','Anagrams Done!','Level '+ana.level,stars,ana.correct,ana.total,()=>{showScreen('anagram')},ana.missed)}

