let dict={level:1,words:[],idx:0,total:10,correct:0,missed:[]};

function startDict(lv){dict.level=lv;const pool=[...getSpellingWords()[lv]];shuffle(pool);dict.words=pool.slice(0,dict.total);dict.idx=0;dict.correct=0;dict.missed=[];hide('dictLevelSelect');show('dictGame');loadDictQ()}

function loadDictQ(){document.getElementById('dictProgress').style.width=(dict.idx/dict.total*100)+'%';document.getElementById('dictProgressText').textContent='Word '+(dict.idx+1)+' of '+dict.total;document.getElementById('dictHint').textContent='';const inp=document.getElementById('dictInput');inp.value='';inp.className='mv-input';inp.style.borderColor='#ab83a1';inp.focus();setTimeout(speakWord,300)}

function speakWord(){if(!window.speechSynthesis)return;window.speechSynthesis.cancel();const u=new SpeechSynthesisUtterance(dict.words[dict.idx].w);u.rate=0.8;u.pitch=1.1;u.lang='en-GB';const sp=document.getElementById('dictSpeaker');sp.classList.add('speaking');u.onend=()=>sp.classList.remove('speaking');window.speechSynthesis.speak(u)}

function checkDictAns(){const inp=document.getElementById('dictInput');const val=inp.value.trim().toLowerCase();const word=dict.words[dict.idx].w.toLowerCase();if(!val)return;if(val===word){dict.correct++;state.spellingCorrect++;checkAch('spell_10',state.spellingCorrect>=10);checkAch('spell_50',state.spellingCorrect>=50);saveState();sfxCorrect();sfxCorrect();inp.className='mv-input flash-correct';setTimeout(()=>{dict.idx++;if(dict.idx>=dict.total)finishDict();else loadDictQ()},400)}else{dict.missed.push({w:word,h:dict.words[dict.idx].h});sfxWrong();sfxWrong();inp.className='mv-input flash-wrong';document.getElementById('dictHint').textContent='It was: '+word;setTimeout(()=>{dict.idx++;if(dict.idx>=dict.total)finishDict();else loadDictQ()},1200)}}

function finishDict(){show('dictLevelSelect');hide('dictGame');const pct=dict.correct/dict.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;if(pct===1)checkAch('perfect_spell',true);checkAch('first_game',true);checkAch('first_dictation',true);if(pct>=0.8)adaptiveCorrect('dictation');else if(pct<0.4)adaptiveWrong('dictation');addStars(stars);recordPlay();showResults('#6a0572','\u{1F50A}','Dictation Done!','Level '+dict.level,stars,dict.correct,dict.total,()=>{showScreen('dictation')},dict.missed)}

document.addEventListener('keydown',function(e){if(document.getElementById('dictation').classList.contains('active')&&document.getElementById('dictGame').style.display!=='none'){if(e.key==='Enter'){e.preventDefault();checkDictAns()}}});

// ==================== MISSING VOWELS ====================
let mv={level:1,words:[],idx:0,total:10,correct:0,missed:[]};
const VOWELS='aeiou';

function removeVowels(w){return w.split('').map(c=>VOWELS.includes(c.toLowerCase())?'_':c).join('')}

function startVowels(lv){mv.level=lv;const pool=[...getSpellingWords()[lv]];shuffle(pool);mv.words=pool.slice(0,mv.total);mv.idx=0;mv.correct=0;mv.missed=[];hide('vowelsLevelSelect');show('vowelsGame');loadMvQ()}

function loadMvQ(){const wordEmoji=getSpellingWordEmoji();const item=mv.words[mv.idx];const word=item.w.toLowerCase();document.getElementById('mvProgress').style.width=(mv.idx/mv.total*100)+'%';document.getElementById('mvProgressText').textContent='Word '+(mv.idx+1)+' of '+mv.total;const pic=document.getElementById('mvPic');const eFn=wordEmoji[word];if(eFn&&EMOJI_SVG[eFn]){pic.innerHTML=EMOJI_SVG[eFn];pic.style.display=''}else{pic.textContent='?';pic.style.display=''};document.getElementById('mvHint').textContent=item.h;const stripped=removeVowels(word);document.getElementById('mvWord').innerHTML=stripped.split('').map(c=>c==='_'?'<span class="mv-gap">_</span>':c).join('');const inp=document.getElementById('mvInput');inp.value='';inp.className='mv-input';inp.focus()}

function checkMvAns(){const inp=document.getElementById('mvInput');const val=inp.value.trim().toLowerCase();const word=mv.words[mv.idx].w.toLowerCase();if(!val)return;if(val===word){mv.correct++;state.spellingCorrect++;checkAch('spell_10',state.spellingCorrect>=10);checkAch('spell_50',state.spellingCorrect>=50);saveState();inp.className='mv-input flash-correct';setTimeout(()=>{mv.idx++;if(mv.idx>=mv.total)finishVowels();else loadMvQ()},400)}else{mv.missed.push({w:word,h:mv.words[mv.idx].h});inp.className='mv-input flash-wrong';document.getElementById('mvHint').textContent='It was: '+word;setTimeout(()=>{mv.idx++;if(mv.idx>=mv.total)finishVowels();else loadMvQ()},1200)}}

function finishVowels(){show('vowelsLevelSelect');hide('vowelsGame');const pct=mv.correct/mv.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;if(pct===1)checkAch('perfect_spell',true);checkAch('first_game',true);if(pct>=0.8)adaptiveCorrect('vowels');else if(pct<0.4)adaptiveWrong('vowels');addStars(stars);recordPlay();showResults('#e84393','_e_','Missing Vowels Done!','Level '+mv.level,stars,mv.correct,mv.total,()=>{showScreen('vowels')},mv.missed)}

// Enter key support for missing vowels
document.addEventListener('keydown',function(e){if(document.getElementById('vowels').classList.contains('active')&&document.getElementById('vowelsGame').style.display!=='none'){if(e.key==='Enter'){e.preventDefault();checkMvAns()}}});

// ==================== NUMBER BONDS ====================
let nb={level:1,target:10,idx:0,total:10,correct:0,answer:'',question:null,missed:[],streak:0};

function startBonds(lv){nb.level=lv;nb.target=lv===1?10:lv===2?20:100;nb.idx=0;nb.correct=0;nb.answer='';nb.missed=[];nb.streak=0;hide('bondsLevelSelect');show('bondsGame');renderNumpad('nbNumpad',nbPress);loadNbQ()}

function genNbQ(target){const format=['A','B','C'][Math.floor(Math.random()*3)];let a,missing;if(target<=10){a=rand(1,target-1)}else if(target<=20){a=rand(1,target-1)}else{a=rand(5,target-5);a=Math.round(a/5)*5}missing=target-a;if(format==='B'){return{format:format,target:target,shown:missing,answer:a,display:'? + '+missing+' = '+target}}else if(format==='C'){const showFirst=Math.random()<0.5;return{format:format,target:target,left:showFirst?a:'?',right:showFirst?'?':missing,answer:showFirst?missing:a,display:'bar'}}else{return{format:format,target:target,shown:a,answer:missing,display:a+' + ? = '+target}}}

function loadNbQ(){nb.question=genNbQ(nb.target);nb.answer='';document.getElementById('nbProgress').style.width=(nb.idx/nb.total*100)+'%';document.getElementById('nbProgressText').textContent='Question '+(nb.idx+1)+' of '+nb.total;const disp=document.getElementById('nbDisplay');const ans=document.getElementById('nbAns');ans.textContent='_';ans.className='nb-ans';if(nb.question.format==='C'){const q=nb.question;disp.innerHTML='<div class="bar-model"><div class="bar-top">'+q.target+'</div><div class="bar-bottom"><div class="bar-part'+(q.left==='?'?' bar-blank':'')+'">'+q.left+'</div><div class="bar-part'+(q.right==='?'?' bar-blank':'')+'">'+q.right+'</div></div></div>'}else{disp.innerHTML='<div class="nb-equation">'+nb.question.display.replace('?','<span class="nb-blank">?</span>')+'</div>'}}

function nbPress(v){if(v==='C'){nb.answer=''}else if(v==='enter'){checkNbAns();return}else{if(nb.answer.length<4)nb.answer+=v}document.getElementById('nbAns').textContent=nb.answer||'_'}

function checkNbAns(){if(!nb.answer)return;var ok=parseInt(nb.answer)===nb.question.answer;var ans=document.getElementById('nbAns');if(ok){nb.correct++;nb.streak=(nb.streak||0)+1;sfxCorrect();ans.className='nb-ans flash-correct';var words=['Yes!','Great!','Nice!','Super!'];ans.textContent=nb.streak>=3?words[Math.floor(Math.random()*words.length)]+' '+nb.streak+'!':nb.question.answer}else{nb.streak=0;nb.missed.push(nb.question);sfxWrong();ans.className='nb-ans flash-wrong';var q=nb.question;var explain=q.format==='B'?q.answer+' + '+q.shown+' = '+q.target:q.format==='C'?(q.left==='?'?q.answer:q.left)+' + '+(q.right==='?'?q.answer:q.right)+' = '+q.target:q.shown+' + '+q.answer+' = '+q.target;ans.textContent=explain}setTimeout(function(){nb.idx++;if(nb.idx>=nb.total)finishBonds();else loadNbQ()},ok?300:800)}

function finishBonds(){show('bondsLevelSelect');hide('bondsGame');checkAch('first_game',true);checkAch('first_bonds',true);const pct=nb.correct/nb.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;if(pct>=0.8)adaptiveCorrect('bonds');else if(pct<0.4)adaptiveWrong('bonds');addStars(stars);recordPlay();const trickyHtml=nb.missed.length>0?nb.missed:null;showResults('#11998e','?+3','Number Bonds Done!','Bonds to '+nb.target,stars,nb.correct,nb.total,()=>{showScreen('bonds')},null);const extra=document.getElementById('missedWords');if(trickyHtml&&trickyHtml.length>0){let h='<div class="tricky-bonds"><div style="font-family:Fredoka One,Comic Sans MS,cursive;font-size:1rem;color:#e17055;margin-bottom:8px;">You found these tricky:</div>';trickyHtml.forEach(q=>{let txt;if(q.format==='B')txt='? + '+q.shown+' = '+q.target+' (answer: '+q.answer+')';else if(q.format==='C'){const l=q.left==='?'?q.answer:q.left;const r=q.right==='?'?q.answer:q.right;txt=l+' + '+r+' = '+q.target}else txt=q.shown+' + ? = '+q.target+' (answer: '+q.answer+')';h+='<div class="tricky-row">'+txt+'</div>'});h+='</div>';extra.innerHTML=h}}

// Keyboard support for number bonds
document.addEventListener('keydown',function(e){if(document.getElementById('bonds').classList.contains('active')&&document.getElementById('bondsGame').style.display!=='none'){if(/^[0-9]$/.test(e.key))nbPress(e.key);else if(e.key==='Enter')nbPress('enter');else if(e.key==='Backspace'||e.key==='Delete')nbPress('C')}});

// ==================== CONFETTI ====================
function launchConfetti(duration){const canvas=document.createElement('canvas');canvas.style.cssText='position:fixed;inset:0;width:100%;height:100%;pointer-events:none;z-index:9999';document.body.appendChild(canvas);const ctx=canvas.getContext('2d');canvas.width=window.innerWidth;canvas.height=window.innerHeight;const colors=['#FFD93D','#FF6B6B','#4ECDC4','#A29BFE','#6BCB77','#FF9A9E','#45B7D1','#F0A500','#E056A0','#00B894'];const pieces=[];for(let i=0;i<80;i++){pieces.push({x:canvas.width*0.5+(Math.random()-0.5)*100,y:canvas.height*0.4,vx:(Math.random()-0.5)*12,vy:-Math.random()*14-4,r:Math.random()*6+3,color:colors[Math.floor(Math.random()*colors.length)],rot:Math.random()*360,vr:(Math.random()-0.5)*10,shape:Math.floor(Math.random()*3),gravity:0.25+Math.random()*0.1,drag:0.98+Math.random()*0.01})}let start=performance.now();function frame(t){const elapsed=t-start;if(elapsed>duration){canvas.remove();return}ctx.clearRect(0,0,canvas.width,canvas.height);const fade=elapsed>duration-400?1-(elapsed-(duration-400))/400:1;ctx.globalAlpha=fade;pieces.forEach(p=>{p.vy+=p.gravity;p.vx*=p.drag;p.x+=p.vx;p.y+=p.vy;p.rot+=p.vr;ctx.save();ctx.translate(p.x,p.y);ctx.rotate(p.rot*Math.PI/180);ctx.fillStyle=p.color;if(p.shape===0){ctx.fillRect(-p.r,-p.r*0.6,p.r*2,p.r*1.2)}else if(p.shape===1){ctx.beginPath();ctx.arc(0,0,p.r,0,Math.PI*2);ctx.fill()}else{ctx.beginPath();ctx.moveTo(0,-p.r);ctx.lineTo(p.r*0.9,p.r*0.7);ctx.lineTo(-p.r*0.9,p.r*0.7);ctx.closePath();ctx.fill()}ctx.restore()});requestAnimationFrame(frame)}requestAnimationFrame(frame)}

// ==================== RESULTS ====================
const ENCOURAGEMENT={3:['Amazing work!','You\'re a superstar!','Absolutely brilliant!','Perfect score — wow!','Top of the class!','Incredible effort!'],2:['Great job!','Well done!','Really good work!','You\'re getting better!','Nearly perfect!','Fantastic effort!'],1:['Good try!','Keep going!','You\'re learning!','Practice makes perfect!','Getting there!','Don\'t give up!'],0:['Let\'s try again!','Every expert was once a beginner!','You\'ll get it next time!','Keep practising!','Learning takes time!','Try a different level?']};
function getEncouragement(stars){const msgs=ENCOURAGEMENT[stars]||ENCOURAGEMENT[0];return msgs[Math.floor(Math.random()*msgs.length)]}
function showResults(color,iconText,title,sub,stars,correct,total,playAgainFn,missed){const activeScreen=document.querySelector('.screen.active');const gameId=activeScreen&&activeScreen.id!=='results'?activeScreen.id:null;if(gameId){ClassmatesAttempts.recordAttempt({pupilName:getCurrentPupil(),gameId:gameId,category:GAME_CATS[gameId]||null,title:title,subtitle:sub,correct:correct,total:total,stars:stars,assignment:getAssignment()})}showScreen('results');const icon=document.getElementById('resultsIcon');icon.style.background='linear-gradient(135deg,'+color+','+lighten(color)+')';icon.textContent=iconText;document.getElementById('resultsTitle').textContent=title;document.getElementById('resultsSub').textContent=getEncouragement(stars);const sr=document.getElementById('starRow');sr.innerHTML='';for(let i=0;i<3;i++){const s=document.createElement('div');s.className='star '+(i<stars?'earned':'empty');s.innerHTML=STAR_SVG;if(i<stars)s.style.animationDelay=(i*0.15)+'s';sr.appendChild(s)}document.getElementById('resultsStats').innerHTML='<div class="rs-item"><div class="rs-num" id="rsCorrect">0/'+total+'</div><div class="rs-lbl">Correct</div></div><div class="rs-item"><div class="rs-num" id="rsScore">0%</div><div class="rs-lbl">Score</div></div>';setTimeout(()=>{const rcEl=document.getElementById('rsCorrect');const rsEl=document.getElementById('rsScore');if(rcEl)animateCounterSuffix(rcEl,correct,'/'+total,600);if(rsEl)animateCounterSuffix(rsEl,Math.round(correct/total*100),'%',600)},100);const mb=document.getElementById('missedWords');if(missed&&missed.length>0){let h='<div style="margin-top:16px;text-align:left;max-width:320px;margin-left:auto;margin-right:auto;"><div style="font-family:Fredoka One,Comic Sans MS,cursive;font-size:1rem;color:#e17055;margin-bottom:8px;">Words I missed:</div>';missed.forEach(m=>{h+='<div style="background:#fff0ed;border:2px solid #fad0c4;border-radius:10px;padding:10px 14px;margin-bottom:6px;"><strong style="text-transform:capitalize;color:#2d3436;">'+(m.w||m.word||'')+'</strong><span style="color:#636e72;font-size:0.85rem;margin-left:8px;">— '+(m.h||m.hint||m.sentence||'')+'</span></div>'});h+='<button id="remixBtn" style="width:100%;margin-top:12px;padding:14px;border:none;border-radius:14px;background:linear-gradient(135deg,#e17055,#d63031);color:white;font-family:Fredoka One,Comic Sans MS,cursive;font-size:1rem;cursor:pointer;box-shadow:0 4px 0 #c0392b">Remix — Try these again!</button>';h+='</div>';mb.innerHTML=h;var remixBtn=document.getElementById('remixBtn');if(remixBtn){remixBtn.onclick=function(){var remixWords=missed.map(function(m){return{w:m.w||m.word||'',h:m.h||m.hint||m.sentence||''}}).filter(function(w){return w.w});if(!remixWords.length){if(playAgainFn)playAgainFn();return}if(gameId==='anagram'){ana.words=remixWords;ana.total=remixWords.length;ana.idx=0;ana.correct=0;ana.missed=[];showScreen('anagram');hide('anagramLevelSelect');show('anagramGame');loadAnaQ()}else if(gameId==='dictation'){dict.words=remixWords;dict.total=remixWords.length;dict.idx=0;dict.correct=0;dict.missed=[];showScreen('dictation');hide('dictLevelSelect');show('dictGame');loadDictQ()}else if(gameId==='vowels'){mv.words=remixWords;mv.total=remixWords.length;mv.idx=0;mv.correct=0;mv.missed=[];showScreen('vowels');hide('vowelsLevelSelect');show('vowelsGame');loadMvQ()}else{sp.words=remixWords;sp.total=remixWords.length;sp.idx=0;sp.correct=0;sp.missed=[];sp.level=sp.level||2;sp.maxLives=sp.level===1?7:sp.level===2?6:5;showScreen('spelling');hide('spellingLevelSelect');show('spellingGame');loadSpellWord()}}}}else{mb.innerHTML=''}let coins=correct+(correct===total?10:0);addCoins(coins);const certBtn=document.getElementById('certBtn');if(stars>=3){certBtn.style.display='inline-flex';certBtn.onclick=()=>printCert(title,sub)}else{certBtn.style.display='none'}document.getElementById('resultsPlayAgain').onclick=playAgainFn;if(stars>=3){sfxLevelUp();launchConfetti(2500)}else if(stars>=2){sfxStreak();launchConfetti(1500)}else if(stars>=1){sfxStreak()}else{sfxWrong()}}
function lighten(hex){return hex+'99'}

// ==================== UTILITIES ====================
function shuffle(a){for(let i=a.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]]}return a}
function rand(min,max){return Math.floor(Math.random()*(max-min+1))+min}
function show(id){const el=document.getElementById(id);el.style.display=el.classList.contains('level-select-wrap')?'flex':''}
function hide(id){document.getElementById(id).style.display='none'}

