function renderAvatarSVG(av,size){return ClassmatesAvatar.renderAvatarSVG(av,size)}
function getAvatarData(pupilName){return ClassmatesAvatar.getAvatarData(pupilName)}
function saveAvatarData(pupilName,av){const saved=ClassmatesAvatar.saveAvatarData(pupilName,av);renderBackupPanel();return saved}
function renderPupilGrid(){return ClassmatesPupilShell.renderPupilGrid(createPupilShellOptions())}
function openAvatarBuilder(){const currentPupil=getCurrentPupil();if(!currentPupil){alert('Select a pupil first');return}ClassmatesAvatar.prepareAvatarForPupil(currentPupil);showScreen('avatarbuilder');renderAvatarBuilder()}
function renderAvatarBuilder(){return ClassmatesAvatar.renderAvatarBuilder()}
function showAvTab(tab,btn){return ClassmatesAvatar.showTab(tab,btn)}
function selectPremade(i){return ClassmatesAvatar.selectPremade(i)}
function finishAvatar(){const currentPupil=getCurrentPupil();if(currentPupil)saveAvatarData(currentPupil,ClassmatesAvatar.getCurrentAvatar());sfxLevelUp();const pupils=getPupils();if(pupils.length>0){renderPupilGrid();showScreen('pupilselect')}else{goHome()}}

// ==================== WORKSHEET GENERATOR ====================
function generateWorksheet(){const lv=parseInt(prompt('Level (1, 2 or 3):','2'))||2;const w=window.open('','_blank');if(!w)return;w.document.write(ClassmatesTeacherTools.buildWorksheetHtml(lv,{getSchoolName:getSchoolName,genMathQuestion:genMathQ,shuffle:shuffle,spellingData:getSpellingWords()}));w.document.close();setTimeout(()=>w.print(),300)}

// ==================== SPACED REPETITION ====================
// Track wrong answers per topic. Mix 20-30% of weak-area questions into future sessions.
function recordWeak(topic,item){state=ClassmatesAppState.addWeakItem(state,topic,item);saveState()}
function getWeakItems(topic,count){return ClassmatesAppState.getWeakItems(state,topic,count)}
function clearWeakItem(topic,item){state=ClassmatesAppState.clearWeakItem(state,topic,item);saveState()}

// ==================== WHITEBOARD MODE ====================
let wb=null;

function launchWhiteboard(){wb=ClassmatesTeacherTools.createWhiteboardSession({randomInt:rand,genMathQuestion:genMathQ});showScreen('whiteboard');loadWbQ()}

function loadWbQ(){const card=ClassmatesTeacherTools.getWhiteboardCard(wb);document.getElementById('wbQuestion').textContent=card.questionText;const ans=document.getElementById('wbAnswer');ans.textContent=card.answerText;ans.classList.add('hidden');if(wb)wb.answerShown=false;document.getElementById('wbShowBtn').textContent='Show Answer';document.getElementById('wbCounter').textContent=card.counterText}

function wbShowAnswer(){const result=ClassmatesTeacherTools.revealWhiteboardAnswer(wb);if(!result.changed)return;document.getElementById('wbAnswer').classList.remove('hidden');document.getElementById('wbShowBtn').textContent='Shown!';sfxCorrect()}

function wbNext(){wb=ClassmatesTeacherTools.nextWhiteboardQuestion(wb,{randomInt:rand,genMathQuestion:genMathQ});loadWbQ()}

document.addEventListener('keydown',function(e){if(document.getElementById('whiteboard').classList.contains('active')){if(e.key===' '||e.key==='Enter'){e.preventDefault();if(!wb||!wb.answerShown)wbShowAnswer();else wbNext()}else if(e.key==='ArrowRight')wbNext()}});

// ==================== ADAPTIVE DIFFICULTY ====================
// Track per-topic streaks. After 3 correct in a row, suggest harder level. After 2 wrong, suggest easier.
function getAdaptiveLevel(topic,defaultLv){if(!state.adaptive[topic])state.adaptive[topic]={streak:0,level:defaultLv};return state.adaptive[topic].level}
function adaptiveCorrect(topic){const result=ClassmatesAppState.adaptiveCorrect(state,topic);saveState();return result}
function adaptiveWrong(topic){const result=ClassmatesAppState.adaptiveWrong(state,topic);saveState();return result}
function getAdaptiveBadge(topic){if(!state.adaptive||!state.adaptive[topic])return'';const lv=state.adaptive[topic].level;const labels=['','&#x1F423;','&#x2B50;','&#x1F680;'];return'<span style="font-size:0.7rem;margin-left:6px;opacity:0.7">'+labels[lv]+'</span>'}
function highlightRecommended(screenId,topic){const lv=getAdaptiveLevel(topic,1);const screen=document.getElementById(screenId);if(!screen)return;screen.querySelectorAll('.level-card').forEach((c,i)=>{c.classList.remove('recommended');c.querySelector('.lc-recommended')?.remove();if(i+1===lv){c.classList.add('recommended');const badge=document.createElement('div');badge.className='lc-recommended';badge.textContent='Recommended';c.appendChild(badge)}})}

// ==================== ENGAGEMENT HELPERS ====================
function flashScreen(correct){const screen=document.querySelector('.screen.active');if(!screen)return;screen.classList.remove('flash-correct-bg','flash-wrong-bg');void screen.offsetWidth;screen.classList.add(correct?'flash-correct-bg':'flash-wrong-bg');screen.addEventListener('animationend',()=>screen.classList.remove('flash-correct-bg','flash-wrong-bg'),{once:true})}
function getGreeting(){const h=new Date().getHours();if(h<12)return'Good morning';if(h<17)return'Good afternoon';return'Good evening'}
function getDayMessage(){var streak=state&&state.streak||0;if(streak>=7)return streak+' day streak! You are unstoppable!';if(streak>=5)return streak+' days in a row! Amazing!';if(streak>=3)return streak+' day streak! Keep it up!';var d=new Date().getDay();var msgs=['Happy Sunday!','Let\'s start the week!','Happy Tuesday!','It\'s Wednesday!','Nearly Friday!','Happy Friday!','Enjoy your Saturday!'];return msgs[d]}
function animateQuestion(elementId){const el=document.getElementById(elementId);if(!el)return;el.classList.remove('q-animate');void el.offsetWidth;el.classList.add('q-animate')}
function animateCounter(el,target,duration){if(!el)return;const start=parseInt(el.textContent)||0;if(start===target)return;const diff=target-start;const startTime=performance.now();function tick(now){const elapsed=now-startTime;const progress=Math.min(elapsed/duration,1);const eased=1-Math.pow(1-progress,3);el.textContent=Math.round(start+diff*eased);if(progress<1)requestAnimationFrame(tick)}requestAnimationFrame(tick)}
function animateCounterSuffix(el,target,suffix,duration){if(!el)return;const startTime=performance.now();function tick(now){const elapsed=now-startTime;const progress=Math.min(elapsed/duration,1);const eased=1-Math.pow(1-progress,3);el.textContent=Math.round(target*eased)+suffix;if(progress<1)requestAnimationFrame(tick)}requestAnimationFrame(tick)}
function showAchPopup(id){const ach=ACHIEVEMENTS.find(a=>a.id===id);if(!ach)return;const div=document.createElement('div');div.className='ach-popup';div.onclick=()=>div.remove();div.innerHTML='<div class="ach-popup-card"><div class="ach-popup-label">Achievement Unlocked!</div><div class="ach-popup-icon">'+ach.icon+'</div><div class="ach-popup-title">'+ach.name+'</div><div class="ach-popup-desc">'+ach.desc+'</div></div>';document.body.appendChild(div);sfxStar();setTimeout(()=>{if(div.parentNode)div.remove()},3000)}
function getWeekNumber(){const d=new Date();const start=new Date(d.getFullYear(),0,1);return Math.ceil(((d-start)/86400000+start.getDay()+1)/7)}
function checkWeeklyGoal(){const week=getWeekNumber();if(state.weeklyGoalReset!==week){state.weeklyGames=0;state.weeklyGoalReset=week;saveState()}}
function renderWeeklyGoal(){checkWeeklyGoal();const goal=10;const progress=Math.min(state.weeklyGames||0,goal);const pct=Math.round(progress/goal*100);const el=document.getElementById('weeklyGoal');if(!el)return;el.innerHTML='<div class="wg-label">Weekly Goal: '+progress+'/'+goal+' games</div><div class="wg-bar"><div class="wg-fill" style="width:'+pct+'%"></div></div>'+(progress>=goal?'<div class="wg-done">\u{1F3AF} Goal Complete!</div>':'')}

// ==================== SOUND ENGINE ====================
let soundMuted=false;
let audioCtx=null;
function getAudioCtx(){if(!audioCtx)audioCtx=new(window.AudioContext||window.webkitAudioContext)();return audioCtx}
function playTone(freq,dur,type,vol){if(soundMuted)return;try{const ctx=getAudioCtx();const o=ctx.createOscillator();const g=ctx.createGain();o.connect(g);g.connect(ctx.destination);o.type=type||'sine';o.frequency.value=freq;g.gain.value=vol||0.3;g.gain.exponentialRampToValueAtTime(0.001,ctx.currentTime+dur);o.start(ctx.currentTime);o.stop(ctx.currentTime+dur)}catch(e){}}
function sfxCorrect(){playTone(523,0.1,'sine',0.25);setTimeout(()=>playTone(659,0.1,'sine',0.25),100);setTimeout(()=>playTone(784,0.15,'sine',0.3),200);flashScreen(true)}
function sfxWrong(){playTone(200,0.15,'square',0.15);setTimeout(()=>playTone(180,0.2,'square',0.12),150);flashScreen(false)}
function sfxStreak(){playTone(523,0.08,'sine',0.2);setTimeout(()=>playTone(659,0.08,'sine',0.2),80);setTimeout(()=>playTone(784,0.08,'sine',0.2),160);setTimeout(()=>playTone(1047,0.2,'sine',0.3),240)}
function sfxLevelUp(){playTone(392,0.1,'sine',0.2);setTimeout(()=>playTone(523,0.1,'sine',0.2),120);setTimeout(()=>playTone(659,0.1,'sine',0.25),240);setTimeout(()=>playTone(784,0.15,'sine',0.3),360);setTimeout(()=>playTone(1047,0.25,'sine',0.35),480)}
function sfxClick(){playTone(800,0.05,'sine',0.1)}
function sfxStar(){playTone(880,0.1,'triangle',0.2);setTimeout(()=>playTone(1108,0.15,'triangle',0.25),120)}
function toggleMute(){soundMuted=!soundMuted;const btn=document.getElementById('muteBtn');if(soundMuted){btn.textContent='\u{1F507} Sound Off';btn.classList.add('muted')}else{btn.textContent='\u{1F50A} Sound On';btn.classList.remove('muted');sfxClick()}}
function toggleDyslexia(){document.body.classList.toggle('dyslexia-mode');const btn=document.getElementById('dyslexiaBtn');btn.classList.toggle('active')}

