const CONT_DATA={1:[{q:'How many continents are there?',correct:'7',opts:['5','6','7','8']},{q:'Which continent do we live on?',correct:'Europe',opts:['Asia','Europe','Africa','North America']},{q:'Which is the largest continent?',correct:'Asia',opts:['Africa','Asia','Europe','North America']},{q:'Which is the smallest continent?',correct:'Australia',opts:['Europe','Australia','Antarctica','South America']},{q:'Which continent is the coldest?',correct:'Antarctica',opts:['Europe','Asia','Antarctica','North America']},{q:'Which continent has the most people?',correct:'Asia',opts:['Europe','Asia','Africa','North America']},{q:'Which continent is Brazil in?',correct:'South America',opts:['North America','South America','Europe','Africa']},{q:'Which continent is Egypt in?',correct:'Africa',opts:['Asia','Africa','Europe','South America']},{q:'Scotland is part of which continent?',correct:'Europe',opts:['Asia','Europe','North America','Africa']},{q:'Penguins live wild on which continent?',correct:'Antarctica',opts:['Europe','Antarctica','Africa','Asia']}],
2:[{q:'How many oceans are there?',correct:'5',opts:['3','4','5','7']},{q:'Which is the largest ocean?',correct:'Pacific',opts:['Atlantic','Pacific','Indian','Arctic']},{q:'Which ocean is between Europe and America?',correct:'Atlantic',opts:['Pacific','Atlantic','Indian','Southern']},{q:'Which is the smallest ocean?',correct:'Arctic',opts:['Indian','Arctic','Southern','Atlantic']},{q:'What is the longest river in the world?',correct:'The Nile',opts:['The Amazon','The Nile','The Mississippi','The Thames']},{q:'What is the highest mountain in the world?',correct:'Mount Everest',opts:['Ben Nevis','Mount Everest','K2','Kilimanjaro']},{q:'What is a desert?',correct:'A very dry area with little rain',opts:['A cold place','A very dry area with little rain','A forest','An island']},{q:'The Sahara Desert is in which continent?',correct:'Africa',opts:['Asia','Africa','Australia','South America']},{q:'What is an island?',correct:'Land surrounded by water',opts:['A mountain','Land surrounded by water','A desert','A forest']},{q:'Which ocean is the warmest?',correct:'Indian',opts:['Atlantic','Pacific','Indian','Arctic']}],
3:[{q:'What is a tropical climate?',correct:'Hot and wet all year',opts:['Cold and dry','Hot and wet all year','Mild with seasons','Freezing']},{q:'What is the equator?',correct:'An imaginary line around the middle of Earth',opts:['A river','An imaginary line around the middle of Earth','A mountain range','A country']},{q:'What are the poles?',correct:'The very top and bottom of Earth',opts:['Mountains','Islands','The very top and bottom of Earth','Deserts']},{q:'What is latitude?',correct:'Distance north or south of the equator',opts:['Distance east or west','Distance north or south of the equator','Height above sea level','Size of a country']},{q:'The Amazon Rainforest is the largest in the world. Where is it?',correct:'South America',opts:['Africa','South America','Asia','North America']},{q:'What causes seasons?',correct:'The tilt of the Earth',opts:['The moon','The tilt of the Earth','Clouds','The sun moving']},{q:'What is a volcano?',correct:'An opening where molten rock escapes',opts:['A very tall mountain','An opening where molten rock escapes','A type of river','A desert']},{q:'What is erosion?',correct:'Wearing away of land by wind or water',opts:['Building of mountains','Wearing away of land by wind or water','A type of weather','Growing of plants']},{q:'What is a glacier?',correct:'A slow-moving river of ice',opts:['A lake','A slow-moving river of ice','A volcano','A desert']},{q:'Greenwich Mean Time (GMT) passes through which country?',correct:'United Kingdom',opts:['France','United Kingdom','USA','Japan']}]};
let cont={level:1,questions:[],idx:0,total:10,correct:0,streak:0};
function startCont(lv){cont.level=lv;cont.questions=[...CONT_DATA[lv]];shuffle(cont.questions);cont.idx=0;cont.correct=0;hide('contLevelSelect');show('contGame');loadContQ()}
function loadContQ(){const q=cont.questions[cont.idx];document.getElementById('contProgress').style.width=(cont.idx/cont.total*100)+'%';document.getElementById('contProgressText').textContent=(cont.idx+1)+'/'+cont.total;document.getElementById('contDisplay').innerHTML='<div class="ph-sound" style="background:#e8f4f0;border-color:#2a9d8f;color:#264653;font-size:1rem">'+q.q+'</div>';const opts=document.getElementById('contOpts');opts.innerHTML='';shuffle([...q.opts]).forEach(o=>{const b=document.createElement('button');b.className='ph-opt';b.textContent=o;b.onclick=()=>{document.querySelectorAll('#contOpts .ph-opt').forEach(x=>{x.classList.add('ph-disabled');if(x.textContent===q.correct)x.classList.add('ph-correct')});if(o===q.correct){cont.correct++;cont.streak=(cont.streak||0)+1;sfxCorrect();b.classList.add('ph-correct');if(cont.streak>=3)b.textContent=o+' \u2714 '+cont.streak+'!'}else{cont.streak=0;sfxWrong();b.classList.add('ph-wrong')}setTimeout(()=>{cont.idx++;if(cont.idx>=cont.total){show('contLevelSelect');hide('contGame');const pct=cont.correct/cont.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;checkAch('first_game',true);checkAch('first_continents',true);addStars(stars);recordPlay();showResults('#264653','\u{1F30D}','World Geography Done!','Level '+cont.level,stars,cont.correct,cont.total,()=>{showScreen('continents')},null)}else loadContQ()},o===q.correct?500:1000)};opts.appendChild(b)})}

