function startWeather(lv){wth.level=lv;wth.questions=[...WEATHER_DATA[lv]];shuffle(wth.questions);wth.idx=0;wth.correct=0;hide('weatherLevelSelect');show('weatherGame');loadWeatherQ()}
function loadWeatherQ(){const q=wth.questions[wth.idx];document.getElementById('weatherProgress').style.width=(wth.idx/wth.total*100)+'%';document.getElementById('weatherProgressText').textContent=(wth.idx+1)+'/'+wth.total;document.getElementById('weatherDisplay').innerHTML='<div class="ph-sound" style="background:#e8f4f8;border-color:#a8dadc;color:#457b9d;font-size:1rem">'+q.q+'</div>';const opts=document.getElementById('weatherOpts');opts.innerHTML='';shuffle([...q.opts]).forEach(o=>{const b=document.createElement('button');b.className='ph-opt';b.textContent=o;b.onclick=()=>{document.querySelectorAll('#weatherOpts .ph-opt').forEach(x=>{x.classList.add('ph-disabled');if(x.textContent===q.correct)x.classList.add('ph-correct')});if(o===q.correct){wth.correct++;wth.streak=(wth.streak||0)+1;sfxCorrect();b.classList.add('ph-correct');if(wth.streak>=3)b.textContent=o+' \u2714 '+wth.streak+'!'}else{wth.streak=0;sfxWrong();b.classList.add('ph-wrong')}setTimeout(()=>{wth.idx++;if(wth.idx>=wth.total){show('weatherLevelSelect');hide('weatherGame');const pct=wth.correct/wth.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;checkAch('first_game',true);checkAch('first_weather',true);addStars(stars);recordPlay();showResults('#457b9d','\u{2600}','Weather Done!','Level '+wth.level,stars,wth.correct,wth.total,()=>{showScreen('weather')},null)}else loadWeatherQ()},o===q.correct?500:1000)};opts.appendChild(b)})}

