function loadFlagQ(){const q=flg.questions[flg.idx];document.getElementById('flagsProgress').style.width=(flg.idx/flg.total*100)+'%';document.getElementById('flagsProgressText').textContent=(flg.idx+1)+'/'+flg.total;document.getElementById('flagsDisplay').innerHTML=q.flag+'<div style="margin-top:12px;font-family:Fredoka One,Comic Sans MS,cursive;font-size:1.1rem;color:#003049">Which country\'s flag is this?</div>';const opts=document.getElementById('flagsOpts');opts.innerHTML='';shuffle([...q.opts]).forEach(o=>{const b=document.createElement('button');b.className='ph-opt';b.textContent=o;b.onclick=()=>{document.querySelectorAll('#flagsOpts .ph-opt').forEach(x=>{x.classList.add('ph-disabled');if(x.textContent===q.correct)x.classList.add('ph-correct')});if(o===q.correct){flg.correct++;flg.streak=(flg.streak||0)+1;sfxCorrect();b.classList.add('ph-correct');if(flg.streak>=3)b.textContent=o+' \u2714 '+flg.streak+'!'}else{flg.streak=0;sfxWrong();b.classList.add('ph-wrong')}setTimeout(()=>{flg.idx++;if(flg.idx>=flg.total){const pct=flg.correct/flg.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;checkAch('first_game',true);checkAch('first_flags',true);addStars(stars);recordPlay();showResults('#003049','\u{1F3F3}','Flags Done!',flg.correct+'/'+flg.total,stars,flg.correct,flg.total,()=>{showScreen('flags');startFlags()},null)}else loadFlagQ()},o===q.correct?500:1000)};opts.appendChild(b)})}

// ==================== MEMORY MATCH ====================
let mem={cards:[],flipped:[],matched:0,total:0,moves:0,busy:false};
function startMemoryMatch(){mem.matched=0;mem.moves=0;mem.flipped=[];mem.busy=false;const allPairs=[{a:'3+7',b:'10'},{a:'6+4',b:'10'},{a:'8+2',b:'10'},{a:'5+5',b:'10'},{a:'9+1',b:'10'},{a:'2\u00D73',b:'6'},{a:'4\u00D75',b:'20'},{a:'7+3',b:'10'},{a:'big',b:'small'},{a:'hot',b:'cold'},{a:'up',b:'down'},{a:'fast',b:'slow'},{a:'happy',b:'sad'},{a:'day',b:'night'},{a:'3\u00D74',b:'12'},{a:'6\u00D76',b:'36'},{a:'half',b:'\u00BD'},{a:'quarter',b:'\u00BC'}];const pairs=shuffle(allPairs);shuffle(pairs);const selected=pairs.slice(0,6);const cards=[];selected.forEach((p,i)=>{cards.push({id:i,text:p.a,pair:i});cards.push({id:i,text:p.b,pair:i})});shuffle(cards);mem.cards=cards;mem.total=selected.length;const grid=document.getElementById('memGrid');grid.innerHTML='';cards.forEach((c,idx)=>{const div=document.createElement('div');div.className='mem-card';div.innerHTML='<div class="mem-face mem-front">?</div><div class="mem-face mem-back">'+c.text+'</div>';div.onclick=()=>flipCard(idx,div);grid.appendChild(div)});document.getElementById('memStatus').textContent='Find all pairs! Moves: 0'}
function flipCard(idx,el){if(mem.busy||el.classList.contains('flipped')||el.classList.contains('matched'))return;el.classList.add('flipped');sfxClick();mem.flipped.push({idx:idx,el:el,pair:mem.cards[idx].pair});if(mem.flipped.length===2){mem.moves++;mem.busy=true;const[a,b]=mem.flipped;if(a.pair===b.pair){mem.matched++;sfxCorrect();a.el.classList.add('matched');b.el.classList.add('matched');mem.flipped=[];mem.busy=false;if(mem.matched>=mem.total){document.getElementById('memStatus').textContent='You did it in '+mem.moves+' moves!';sfxLevelUp();const stars=mem.moves<=8?3:mem.moves<=12?2:1;addStars(stars);recordPlay();checkAch('first_game',true);checkAch('first_memory',true);setTimeout(()=>showResults('#e056a0','\u{1F0CF}','Memory Match!',mem.moves+' moves',stars,mem.total,mem.total,()=>{showScreen('memorymatch');startMemoryMatch()},null),1500)}else{document.getElementById('memStatus').textContent='Pairs: '+mem.matched+'/'+mem.total+' | Moves: '+mem.moves}}else{sfxWrong();setTimeout(()=>{a.el.classList.remove('flipped');b.el.classList.remove('flipped');mem.flipped=[];mem.busy=false},800);document.getElementById('memStatus').textContent='Pairs: '+mem.matched+'/'+mem.total+' | Moves: '+mem.moves}}}

