function loadGramQ(){const q=gram.questions[gram.idx];document.getElementById('gramProgress').style.width=(gram.idx/gram.total*100)+'%';document.getElementById('gramProgressText').textContent=(gram.idx+1)+'/'+gram.total;document.getElementById('gramDisplay').innerHTML='<div class="ph-sound" style="background:#f0f0f0;border-color:#b2bec3;color:#636e72">What type of word is "<strong>'+q.w+'</strong>"?</div>';const opts=document.getElementById('gramOpts');opts.innerHTML='';shuffle([...q.opts]).forEach(o=>{const b=document.createElement('button');b.className='ph-opt';b.textContent=o;b.onclick=()=>{document.querySelectorAll('#gramOpts .ph-opt').forEach(x=>{x.classList.add('ph-disabled');if(x.textContent===q.a)x.classList.add('ph-correct')});if(o===q.a){gram.correct++;sfxCorrect();b.classList.add('ph-correct')}else{sfxWrong();b.classList.add('ph-wrong')}setTimeout(()=>{gram.idx++;if(gram.idx>=gram.total)finishGrammar();else loadGramQ()},o===q.a?500:1000)};opts.appendChild(b)})}
