let bee={words:[],idx:0,lives:3,score:0};
function startBee(){const spellingWords=getSpellingWords();const allWords=[...spellingWords[1],...spellingWords[2],...spellingWords[3]];shuffle(allWords);bee.words=allWords;bee.idx=0;bee.lives=3;bee.score=0;showScreen('spellingbee');loadBeeWord()}
function loadBeeWord(){const wordEmoji=getSpellingWordEmoji();const item=bee.words[bee.idx%bee.words.length];document.getElementById('beeLives').innerHTML='\u{2764}\u{FE0F}'.repeat(bee.lives)+'\u{1F5A4}'.repeat(3-bee.lives);const pic=document.getElementById('beePic');const eFn=wordEmoji[item.w];if(eFn&&EMOJI_SVG[eFn]){pic.innerHTML=EMOJI_SVG[eFn];pic.style.display=''}else{pic.style.display='none'};document.getElementById('beeHint').textContent=item.h;document.getElementById('beeInput').value='';document.getElementById('beeInput').focus();document.getElementById('beeScore').textContent='Score: '+bee.score}
function checkBee(){const val=document.getElementById('beeInput').value.trim().toLowerCase();const word=bee.words[bee.idx%bee.words.length].w.toLowerCase();if(!val)return;if(val===word){bee.score++;bee.idx++;sfxCorrect();loadBeeWord()}else{bee.lives--;sfxWrong();document.getElementById('beeLives').innerHTML='\u{2764}\u{FE0F}'.repeat(Math.max(0,bee.lives))+'\u{1F5A4}'.repeat(3-Math.max(0,bee.lives));if(bee.lives<=0){const stars=bee.score>=15?3:bee.score>=8?2:bee.score>=3?1:0;addStars(stars);recordPlay();checkAch('first_game',true);checkAch('first_bee',true);showResults('#fdcb6e','\u{1F41D}','Spelling Bee!','Score: '+bee.score,stars,bee.score,bee.score+1,()=>{showScreen('spellingbee');startBee()},null)}else{document.getElementById('beeInput').value='';document.getElementById('beeInput').focus()}}}
document.addEventListener('keydown',function(e){if(document.getElementById('spellingbee').classList.contains('active')&&e.key==='Enter'){e.preventDefault();checkBee()}});

