let seq={level:1,idx:0,total:10,correct:0};
function genSeqQ(lv){let start,step;if(lv===1){step=rand(1,2);start=rand(1,10)}else if(lv===2){step=[2,5,10][rand(0,2)];start=rand(0,3)*step}else{step=rand(3,12);start=rand(1,10)}const nums=[];for(let i=0;i<5;i++)nums.push(start+step*i);const miss=rand(1,3);const ans=nums[miss];nums[miss]='?';const wrongs=[ans+step,ans-step,ans+rand(1,5)].filter(x=>x>0&&x!==ans);return{display:nums.join(', '),correct:String(ans),opts:shuffle([String(ans),...wrongs.map(String)]).slice(0,4)}}
function startSeq(lv){seq.level=lv;seq.idx=0;seq.correct=0;hide('seqLevelSelect');show('seqGame');loadSeqQ()}
function loadSeqQ(){const q=genSeqQ(seq.level);seq.question=q;document.getElementById('seqProgress').style.width=(seq.idx/seq.total*100)+'%';document.getElementById('seqProgressText').textContent=(seq.idx+1)+'/'+seq.total;document.getElementById('seqDisplay').innerHTML='<div class="ph-sound" style="background:#e8fffe;border-color:#81ecec;color:#00cec9;font-size:1.3rem">'+q.display+'</div>';const opts=document.getElementById('seqOpts');opts.innerHTML='';q.opts.forEach(o=>{const b=document.createElement('button');b.className='ph-opt';b.textContent=o;b.onclick=()=>{document.querySelectorAll('#seqOpts .ph-opt').forEach(x=>{x.classList.add('ph-disabled');if(x.textContent===q.correct)x.classList.add('ph-correct')});if(o===q.correct){seq.correct++;sfxCorrect();b.classList.add('ph-correct')}else{sfxWrong();b.classList.add('ph-wrong')}setTimeout(()=>{seq.idx++;if(seq.idx>=seq.total)finishSeq();else loadSeqQ()},o===q.correct?500:1000)};opts.appendChild(b)})}
function finishSeq(){show('seqLevelSelect');hide('seqGame');const pct=seq.correct/seq.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;checkAch('first_game',true);checkAch('first_sequence',true);addStars(stars);recordPlay();showResults('#00cec9','1,2,?','Sequences Done!','Level '+seq.level,stars,seq.correct,seq.total,()=>{showScreen('sequence')},null)}

