function finishCQ(){const pct=cq.correct/cq.total;const stars=pct>=.9?3:pct>=.6?2:pct>=.3?1:0;checkAch('first_game',true);addStars(stars);recordPlay();showResults('#e17055','\u{270D}','Quiz Done!',cq.correct+'/'+cq.total,stars,cq.correct,cq.total,()=>{showScreen('customquiz');startCustomQuiz()},null)}

