const POWERUPS=[
  {id:'extra_life',name:'Extra Life',desc:'+1 life in spelling',cost:15,icon:'\u2764\uFE0F',stackable:true},
  {id:'reveal_letter',name:'Reveal Letter',desc:'Show one letter free',cost:10,icon:'\uD83D\uDCA1',stackable:true},
  {id:'skip_question',name:'Skip Question',desc:'Skip without penalty',cost:20,icon:'\u23ED\uFE0F',stackable:true},
  {id:'freeze_timer',name:'Freeze Timer',desc:'Pause timer for 5s',cost:25,icon:'\u2744\uFE0F',stackable:true},
  {id:'double_coins',name:'Double Coins',desc:'2x coins next game',cost:30,icon:'\u2728',stackable:false},
];
function buyPowerup(id){
  const pu=POWERUPS.find(p=>p.id===id);
  if(!pu||state.coins<pu.cost)return;
  state.coins-=pu.cost;
  if(!state.powerups)state.powerups={};
  state.powerups[id]=(state.powerups[id]||0)+1;
  saveState();updateCoinDisplay();renderShop();sfxClick();
}
function usePowerup(id){
  if(!state.powerups||!state.powerups[id]||state.powerups[id]<=0)return false;
  state.powerups[id]--;
  saveState();
  return true;
}
function getPowerupCount(id){return(state.powerups&&state.powerups[id])||0}

