function renderJourney(){
  const map=document.getElementById('journeyMap');
  const starsEl=document.getElementById('journeyStars');
  if(!map)return;
  starsEl.textContent='\u2B50 '+state.stars+' stars';

  // Find current position (highest unlocked stop)
  let currentIdx=0;
  JOURNEY_STOPS.forEach(function(stop,i){
    if(state.stars>=stop.stars)currentIdx=i;
  });

  // Check if new stop was unlocked (for celebration)
  const lastJourneyStop=state.journeyStop||0;
  if(currentIdx>lastJourneyStop){
    state.journeyStop=currentIdx;
    saveState();
    // Celebrate after render
    setTimeout(function(){
      var stop=JOURNEY_STOPS[currentIdx];
      launchConfetti(2000);
      sfxLevelUp();
      var popup=document.createElement('div');
      popup.className='ach-popup';
      popup.onclick=function(){popup.remove()};
      popup.innerHTML='<div class="ach-popup-card"><div class="ach-popup-label">New Location Unlocked!</div><div class="ach-popup-icon">'+stop.emoji+'</div><div class="ach-popup-title">'+stop.name+'</div><div class="ach-popup-desc">'+stop.fact+'</div></div>';
      document.body.appendChild(popup);
      setTimeout(function(){if(popup.parentNode)popup.remove()},4000);
    },500);
  }

  var currentPupil=getCurrentPupil();
  var av=currentPupil?getAvatarData(currentPupil):{premade:null,skin:0,hair:0,hairColor:0,eyes:0,mouth:0,outfit:0,accessory:0};

  var h='<div class="journey-path"></div>';
  h+='<div class="journey-start-badge">\u{1F4CD} Your journey starts here</div>';

  JOURNEY_STOPS.forEach(function(stop,i){
    var unlocked=state.stars>=stop.stars;
    var isCurrent=i===currentIdx;
    var statusClass=isCurrent?'current':(unlocked?'unlocked':'locked');

    h+='<div class="journey-stop">';
    h+='<div class="stop-node '+statusClass+'">'+stop.emoji+'</div>';
    if(isCurrent){
      h+='<div class="stop-avatar">'+renderAvatarSVG(av,28)+'</div>';
    }
    h+='<div class="stop-card '+statusClass+'">';
    h+='<div class="stop-name">'+stop.name+'</div>';
    h+='<div class="stop-desc">'+stop.desc+'</div>';
    if(unlocked){
      h+='<div class="stop-fact">'+stop.fact+'</div>';
    } else {
      h+='<div class="stop-stars">\u{1F512} '+stop.stars+' stars to unlock</div>';
    }
    h+='</div>';
    h+='</div>';
  });

  h+='<div class="journey-end-badge"><div class="end-emoji">\u{1F3C6}</div><div class="end-text">Journey Complete!</div><div class="end-sub">Earn '+JOURNEY_STOPS[JOURNEY_STOPS.length-1].stars+' stars to finish</div></div>';

  map.innerHTML=h;

  // Scroll to current position
  setTimeout(function(){
    var currentNode=map.querySelector('.stop-node.current');
    if(currentNode)currentNode.scrollIntoView({behavior:'smooth',block:'center'});
  },300);
}

// ==================== HIGHLAND DASH ====================
(function(){
var HD={
  active:false,renderer:null,scene:null,camera:null,clock:null,
  vehicle:null,road:null,roadSegs:[],envObjs:[],
  speed:0,baseSpeed:12,maxSpeed:24,minSpeed:6,
  steerX:0,steerTarget:0,steerSpeed:6,
  roadWidth:8,laneWidth:6,
  distance:0,lives:3,streak:0,score:0,
  keys:{left:false,right:false},
  splinePoints:[],splineCurve:null,
  tParam:0,segLength:200,totalGenerated:0,
  frameId:null,
  // Road generation state
  roadMeshes:[],treeMeshes:null,wallMeshes:null,
  treeCount:400,wallCount:200,
  treeMatrix:null,wallMatrix:null,
  treeIdx:0,wallIdx:0,
  fog:null
};

// Colour palette
var C={
  road:0x2d2d2d,roadMark:0xffffff,
  grass:0x4a7c59,grassDark:0x3a6c49,
  hillFar:0x6b8f71,mountain:0x7b6d8d,
  skyTop:0x87CEEB,skyHorizon:0xE0F0FF,
  tree:0x2d5a27,treeTrunk:0x5c3d2e,
  wall:0x8b7355,
  vanRed:0xcc3333,vanLight:0xffeeaa,
  wheelDark:0x222222,wheelRim:0x666666
};

function buildVehicle(){
  var g=new THREE.Group();
  // Body
  var body=new THREE.Mesh(
    new THREE.BoxGeometry(1.8,0.7,3.2),
    new THREE.MeshLambertMaterial({color:C.vanRed,flatShading:true})
  );
  body.position.y=0.55;
  g.add(body);
  // Cabin (upper part)
  var cabin=new THREE.Mesh(
    new THREE.BoxGeometry(1.6,0.6,1.6),
    new THREE.MeshLambertMaterial({color:C.vanRed,flatShading:true})
  );
  cabin.position.set(0,1.1,-0.3);
  g.add(cabin);
  // Windscreen
  var wind=new THREE.Mesh(
    new THREE.BoxGeometry(1.4,0.45,0.05),
    new THREE.MeshLambertMaterial({color:0x88bbdd,flatShading:true,transparent:true,opacity:0.7})
  );
  wind.position.set(0,1.05,0.5);
  wind.rotation.x=-0.2;
  g.add(wind);
  // Rear window
  var rwind=new THREE.Mesh(
    new THREE.BoxGeometry(1.4,0.4,0.05),
    new THREE.MeshLambertMaterial({color:0x88bbdd,flatShading:true,transparent:true,opacity:0.6})
  );
  rwind.position.set(0,1.05,-1.1);
  rwind.rotation.x=0.15;
  g.add(rwind);
  // Headlights
  [-0.6,0.6].forEach(function(x){
    var hl=new THREE.Mesh(
      new THREE.SphereGeometry(0.12,6,4),
      new THREE.MeshLambertMaterial({color:C.vanLight,emissive:0xffdd88,emissiveIntensity:0.5,flatShading:true})
    );
    hl.position.set(x,0.5,1.6);
    g.add(hl);
  });
  // Wheels
  var wheelGeo=new THREE.CylinderGeometry(0.3,0.3,0.2,8);
  var wheelMat=new THREE.MeshLambertMaterial({color:C.wheelDark,flatShading:true});
  var positions=[[-0.9,0.3,1],[-0.9,0.3,-1],[0.9,0.3,1],[0.9,0.3,-1]];
  HD.wheels=[];
  positions.forEach(function(p){
    var w=new THREE.Mesh(wheelGeo,wheelMat);
    w.rotation.z=Math.PI/2;
    w.position.set(p[0],p[1],p[2]);
    g.add(w);
    HD.wheels.push(w);
  });
  return g;
}

function generateRoadPoints(count,startIdx){
  var pts=[];
  for(var i=0;i<count;i++){
    var idx=startIdx+i;
    var z=-idx*10;
    var x=Math.sin(idx*0.03)*20+Math.sin(idx*0.007)*40;
    var y=Math.sin(idx*0.015)*4+Math.cos(idx*0.008)*6;
    if(y<0)y*=0.3;
    pts.push(new THREE.Vector3(x,y,z));
  }
  return pts;
}

function buildRoadMesh(curve,tStart,tEnd,samples){
  var pts=[];
  var uvs=[];
  var indices=[];
  var hw=HD.roadWidth/2;
  for(var i=0;i<=samples;i++){
    var t=tStart+(tEnd-tStart)*(i/samples);
    var p=curve.getPointAt(Math.min(t,1));
    var tan=curve.getTangentAt(Math.min(t,1)).normalize();
    var up=new THREE.Vector3(0,1,0);
    var right=new THREE.Vector3().crossVectors(tan,up).normalize();
    pts.push(p.x-right.x*hw, p.y-0.01, p.z-right.z*hw);
    pts.push(p.x+right.x*hw, p.y-0.01, p.z+right.z*hw);
    uvs.push(0,i/samples);
    uvs.push(1,i/samples);
    if(i<samples){
      var a=i*2,b=i*2+1,c=(i+1)*2,d=(i+1)*2+1;
      indices.push(a,c,b);
      indices.push(b,c,d);
    }
  }
  var geo=new THREE.BufferGeometry();
  geo.setAttribute('position',new THREE.Float32BufferAttribute(pts,3));
  geo.setAttribute('uv',new THREE.Float32BufferAttribute(uvs,2));
  geo.setIndex(indices);
  geo.computeVertexNormals();

  // Road markings via canvas texture
  var tc=document.createElement('canvas');
  tc.width=64;tc.height=256;
  var ctx=tc.getContext('2d');
  ctx.fillStyle='#2d2d2d';
  ctx.fillRect(0,0,64,256);
  // Centre line dashes
  ctx.fillStyle='#ffffff';
  for(var d=0;d<256;d+=32){
    ctx.fillRect(30,d,4,20);
  }
  // Edge lines
  ctx.fillStyle='rgba(255,255,255,0.3)';
  ctx.fillRect(4,0,2,256);
  ctx.fillRect(58,0,2,256);
  var tex=new THREE.CanvasTexture(tc);
  tex.wrapS=THREE.RepeatWrapping;
  tex.wrapT=THREE.RepeatWrapping;
  tex.repeat.set(1,samples/4);

  var mat=new THREE.MeshLambertMaterial({map:tex,flatShading:true});
  return new THREE.Mesh(geo,mat);
}

function buildGround(){
  // Flat ground far below for the distant floor
  var geo=new THREE.PlaneGeometry(2000,2000,1,1);
  var mat=new THREE.MeshLambertMaterial({color:C.grassDark,flatShading:true});
  var mesh=new THREE.Mesh(geo,mat);
  mesh.rotation.x=-Math.PI/2;
  mesh.position.y=-2;
  return mesh;
}

function buildTerrainStrips(curve,samples){
  // Build grass strips either side of the road that follow the road elevation
  var group=new THREE.Group();
  var hw=HD.roadWidth/2;
  var stripWidth=80; // how far the terrain extends from road edge
  var mat=new THREE.MeshLambertMaterial({color:C.grass,flatShading:true});
  var matFar=new THREE.MeshLambertMaterial({color:C.hillFar,flatShading:true});

  [-1,1].forEach(function(side){
    var pts=[];
    var uvs=[];
    var indices=[];
    for(var i=0;i<=samples;i++){
      var t=i/samples;
      var p=curve.getPointAt(Math.min(t,0.999));
      var tan=curve.getTangentAt(Math.min(t,0.999)).normalize();
      var up=new THREE.Vector3(0,1,0);
      var right=new THREE.Vector3().crossVectors(tan,up).normalize();
      // Inner edge (road edge)
      var innerX=p.x+right.x*side*hw;
      var innerZ=p.z+right.z*side*hw;
      var innerY=p.y-0.02;
      // Outer edge (far from road)
      var outerX=p.x+right.x*side*(hw+stripWidth);
      var outerZ=p.z+right.z*side*(hw+stripWidth);
      var outerY=p.y-0.5+Math.sin(i*0.05)*2; // gentle rolling hills
      pts.push(innerX,innerY,innerZ);
      pts.push(outerX,outerY,outerZ);
      uvs.push(0,t); uvs.push(1,t);
      if(i<samples){
        var a=i*2,b=i*2+1,c=(i+1)*2,d=(i+1)*2+1;
        if(side===1){indices.push(a,c,b);indices.push(b,c,d)}
        else{indices.push(a,b,c);indices.push(b,d,c)}
      }
    }
    var geo=new THREE.BufferGeometry();
    geo.setAttribute('position',new THREE.Float32BufferAttribute(pts,3));
    geo.setAttribute('uv',new THREE.Float32BufferAttribute(uvs,2));
    geo.setIndex(indices);
    geo.computeVertexNormals();
    group.add(new THREE.Mesh(geo,mat));
  });
  return group;
}

function buildSky(){
  var geo=new THREE.SphereGeometry(800,16,12);
  var mat=new THREE.ShaderMaterial({
    uniforms:{
      topColor:{value:new THREE.Color(C.skyTop)},
      bottomColor:{value:new THREE.Color(C.skyHorizon)},
      offset:{value:20},
      exponent:{value:0.4}
    },
    vertexShader:[
      'varying vec3 vWorldPosition;',
      'void main(){',
      '  vec4 wp=modelMatrix*vec4(position,1.0);',
      '  vWorldPosition=wp.xyz;',
      '  gl_Position=projectionMatrix*modelViewMatrix*vec4(position,1.0);',
      '}'
    ].join('\n'),
    fragmentShader:[
      'uniform vec3 topColor;',
      'uniform vec3 bottomColor;',
      'uniform float offset;',
      'uniform float exponent;',
      'varying vec3 vWorldPosition;',
      'void main(){',
      '  float h=normalize(vWorldPosition+vec3(0,offset,0)).y;',
      '  gl_FragColor=vec4(mix(bottomColor,topColor,max(pow(max(h,0.0),exponent),0.0)),1.0);',
      '}'
    ].join('\n'),
    side:THREE.BackSide
  });
  return new THREE.Mesh(geo,mat);
}

function buildTrees(curve){
  var tGeo=new THREE.ConeGeometry(1.2,3.5,6);
  var tMat=new THREE.MeshLambertMaterial({color:C.tree,flatShading:true});
  var trunkGeo=new THREE.CylinderGeometry(0.15,0.2,1.2,5);
  var trunkMat=new THREE.MeshLambertMaterial({color:C.treeTrunk,flatShading:true});
  // Merge into single geometry for performance: use groups
  var group=new THREE.Group();
  var hw=HD.roadWidth/2;
  for(var i=0;i<HD.treeCount;i++){
    var t=Math.random()*0.95;
    var p=curve.getPointAt(t);
    var tan=curve.getTangentAt(t).normalize();
    var up=new THREE.Vector3(0,1,0);
    var right=new THREE.Vector3().crossVectors(tan,up).normalize();
    var side=(Math.random()<0.5?-1:1);
    var offset=hw+3+Math.random()*25;
    var x=p.x+right.x*side*offset;
    var z=p.z+right.z*side*offset;
    var y=p.y-0.5;
    var scale=0.6+Math.random()*0.8;
    var trunk=new THREE.Mesh(trunkGeo,trunkMat);
    trunk.position.set(x,y+0.6*scale,z);
    trunk.scale.set(scale,scale,scale);
    group.add(trunk);
    var crown=new THREE.Mesh(tGeo,tMat);
    crown.position.set(x,y+2.5*scale,z);
    crown.scale.set(scale,scale,scale);
    group.add(crown);
  }
  return group;
}

function buildWalls(curve){
  var wallGeo=new THREE.BoxGeometry(0.6,0.8,3);
  var wallMat=new THREE.MeshLambertMaterial({color:C.wall,flatShading:true});
  var group=new THREE.Group();
  var hw=HD.roadWidth/2;
  for(var i=0;i<HD.wallCount;i++){
    var t=(i/HD.wallCount)*0.95;
    var p=curve.getPointAt(t);
    var tan=curve.getTangentAt(t).normalize();
    var up=new THREE.Vector3(0,1,0);
    var right=new THREE.Vector3().crossVectors(tan,up).normalize();
    // Place walls on both sides
    [-1,1].forEach(function(side){
      if(Math.random()>0.4)return; // sparse
      var offset=hw+1+Math.random()*2;
      var w=new THREE.Mesh(wallGeo,wallMat);
      w.position.set(
        p.x+right.x*side*offset,
        p.y+0.1,
        p.z+right.z*side*offset
      );
      // Align wall with road direction
      var angle=Math.atan2(tan.x,tan.z);
      w.rotation.y=angle;
      group.add(w);
    });
  }
  return group;
}

function buildMountains(){
  var group=new THREE.Group();
  var mGeo=new THREE.ConeGeometry(80,120,6);
  var mMat=new THREE.MeshLambertMaterial({color:C.mountain,flatShading:true});
  var hGeo=new THREE.SphereGeometry(60,6,4);
  var hMat=new THREE.MeshLambertMaterial({color:C.hillFar,flatShading:true});
  for(var i=0;i<12;i++){
    var angle=i*(Math.PI*2/12)+Math.random()*0.3;
    var dist=300+Math.random()*200;
    var m=new THREE.Mesh(mGeo,mMat);
    m.position.set(Math.cos(angle)*dist, 20+Math.random()*30, Math.sin(angle)*dist-500);
    m.scale.set(0.5+Math.random()*0.8, 0.4+Math.random()*0.6, 0.5+Math.random()*0.8);
    group.add(m);
  }
  for(var j=0;j<20;j++){
    var a2=Math.random()*Math.PI*2;
    var d2=150+Math.random()*300;
    var h=new THREE.Mesh(hGeo,hMat);
    h.position.set(Math.cos(a2)*d2, -20+Math.random()*10, Math.sin(a2)*d2-400);
    h.scale.set(1+Math.random(),0.3+Math.random()*0.3,1+Math.random());
    group.add(h);
  }
  return group;
}

window.hdashInit=function(){
  var canvas=document.getElementById('hdash-canvas');
  var container=document.getElementById('hdash');
  // Clean up previous
  hdashStop();

  // Renderer
  HD.renderer=new THREE.WebGLRenderer({canvas:canvas,antialias:true});
  HD.renderer.setPixelRatio(Math.min(window.devicePixelRatio,2));
  HD.renderer.setSize(container.clientWidth,container.clientHeight);
  HD.renderer.setClearColor(C.skyHorizon);

  // Scene
  HD.scene=new THREE.Scene();
  HD.fog=new THREE.Fog(C.skyHorizon,150,500);
  HD.scene.fog=HD.fog;

  // Camera
  HD.camera=new THREE.PerspectiveCamera(65,container.clientWidth/container.clientHeight,0.5,600);

  // Lighting
  var ambient=new THREE.AmbientLight(0xcccccc,0.6);
  HD.scene.add(ambient);
  var sun=new THREE.DirectionalLight(0xfff5e0,0.8);
  sun.position.set(50,100,-50);
  HD.scene.add(sun);
  var fill=new THREE.DirectionalLight(0x88aacc,0.3);
  fill.position.set(-30,40,50);
  HD.scene.add(fill);

  // Sky
  HD.scene.add(buildSky());

  // Ground plane
  HD.ground=buildGround();
  HD.scene.add(HD.ground);

  // Generate road spline
  HD.splinePoints=generateRoadPoints(200,0);
  HD.splineCurve=new THREE.CatmullRomCurve3(HD.splinePoints,false,'catmullrom',0.5);
  HD.totalGenerated=200;

  // Build road mesh
  var road=buildRoadMesh(HD.splineCurve,0,1,800);
  HD.scene.add(road);
  HD.roadMeshes.push(road);

  // Terrain strips (grass either side of road following elevation)
  var terrain=buildTerrainStrips(HD.splineCurve,800);
  HD.scene.add(terrain);
  HD.envObjs.push(terrain);

  // Trees
  var trees=buildTrees(HD.splineCurve);
  HD.scene.add(trees);
  HD.envObjs.push(trees);

  // Stone walls
  var walls=buildWalls(HD.splineCurve);
  HD.scene.add(walls);
  HD.envObjs.push(walls);

  // Mountains
  var mountains=buildMountains();
  HD.scene.add(mountains);
  HD.envObjs.push(mountains);

  // Vehicle
  HD.vehicle=buildVehicle();
  var startPos=HD.splineCurve.getPointAt(0);
  HD.vehicle.position.copy(startPos);
  HD.vehicle.position.y+=0.15;
  HD.scene.add(HD.vehicle);

  // State
  HD.speed=HD.baseSpeed;
  HD.steerX=0;
  HD.steerTarget=0;
  HD.distance=0;
  HD.lives=3;
  HD.streak=0;
  HD.tParam=0;
  HD.active=true;
  HD.clock=new THREE.Clock();

  // HUD
  document.getElementById('hdashHud').style.display='block';
  updateHUD();

  // Input
  HD._keydown=function(e){
    if(!HD.active)return;
    if(e.key==='ArrowLeft'||e.key==='a')HD.keys.left=true;
    if(e.key==='ArrowRight'||e.key==='d')HD.keys.right=true;
  };
  HD._keyup=function(e){
    if(e.key==='ArrowLeft'||e.key==='a')HD.keys.left=false;
    if(e.key==='ArrowRight'||e.key==='d')HD.keys.right=false;
  };
  HD._resize=function(){
    var w=container.clientWidth,h=container.clientHeight;
    HD.camera.aspect=w/h;
    HD.camera.updateProjectionMatrix();
    HD.renderer.setSize(w,h);
  };
  window.addEventListener('keydown',HD._keydown);
  window.addEventListener('keyup',HD._keyup);
  window.addEventListener('resize',HD._resize);

  // Touch controls
  HD._touchStartX=null;
  HD._touchmove=function(e){
    if(!HD.active)return;
    var touch=e.touches[0];
    var cx=container.clientWidth/2;
    var dx=(touch.clientX-cx)/cx; // -1 to 1
    HD.steerTarget=dx*HD.laneWidth*0.5;
  };
  HD._touchend=function(){
    HD.steerTarget=0;
  };
  canvas.addEventListener('touchmove',HD._touchmove,{passive:true});
  canvas.addEventListener('touchend',HD._touchend);

  // Start loop
  animate();
};

function updateHUD(){
  var mph=Math.round(HD.speed*5);
  document.getElementById('hdashSpeed').textContent=mph;
  document.getElementById('hdashDist').textContent=Math.round(HD.distance);
  var livesStr='';
  for(var i=0;i<HD.lives;i++)livesStr+='\u{1F404}';
  document.getElementById('hdashLives').textContent=livesStr;
  document.getElementById('hdashStreak').textContent=HD.streak>=2?'\u{1F525} x'+HD.streak:'';
}

function animate(){
  if(!HD.active)return;
  HD.frameId=requestAnimationFrame(animate);
  var delta=HD.clock.getDelta();
  if(delta>0.1)delta=0.1; // clamp

  // Steering
  if(HD.keys.left)HD.steerTarget=-HD.laneWidth*0.45;
  else if(HD.keys.right)HD.steerTarget=HD.laneWidth*0.45;
  else if(!HD._touchStartX)HD.steerTarget*=0.9; // drift back to centre

  HD.steerX+=(HD.steerTarget-HD.steerX)*Math.min(1,HD.steerSpeed*delta);

  // Speed increases slowly over time
  HD.speed=Math.min(HD.maxSpeed,HD.speed+delta*0.15);

  // Move along spline
  var curveLen=HD.splineCurve.getLength();
  var moveAmt=HD.speed*delta;
  HD.tParam+=moveAmt/curveLen;
  HD.distance+=moveAmt;

  if(HD.tParam>0.95){
    // Approaching end — wrap or extend
    HD.tParam=0.95;
  }

  var t=Math.max(0,Math.min(HD.tParam,0.999));
  var pos=HD.splineCurve.getPointAt(t);
  var tan=HD.splineCurve.getTangentAt(t).normalize();
  var up=new THREE.Vector3(0,1,0);
  var right=new THREE.Vector3().crossVectors(tan,up).normalize();

  // Sample a point slightly ahead for slope alignment
  var tAhead=Math.min(t+2/HD.splineCurve.getLength(),0.999);
  var posAhead=HD.splineCurve.getPointAt(tAhead);

  // Vehicle position (offset by steer)
  var vx=pos.x+right.x*HD.steerX;
  var vz=pos.z+right.z*HD.steerX;
  var vy=pos.y+0.4;
  HD.vehicle.position.set(vx,vy,vz);

  // Build orientation matrix manually to avoid lookAt flip
  // Forward = tangent direction projected with slope
  var forward=new THREE.Vector3().subVectors(posAhead,pos).normalize();
  // Right = forward x world up
  var vRight=new THREE.Vector3().crossVectors(forward,up).normalize();
  // Recalculate true up from right x forward
  var vUp=new THREE.Vector3().crossVectors(vRight,forward).normalize();

  // Build rotation matrix
  var rotMatrix=new THREE.Matrix4();
  rotMatrix.makeBasis(vRight,vUp,forward.clone().negate());
  HD.vehicle.quaternion.setFromRotationMatrix(rotMatrix);

  // Add steering tilt on top
  var tiltAmt=HD.steerX/HD.laneWidth;
  HD.vehicle.rotateOnAxis(new THREE.Vector3(0,0,1),-tiltAmt*0.3);

  // Wheel spin
  var wheelRot=HD.speed*delta*5;
  HD.wheels.forEach(function(w){w.rotation.x+=wheelRot});

  // Camera follows behind and above — sample actual road position behind
  var camHeight=3.5;
  var tBehind=Math.max(t-8/curveLen,0.001);
  var posBehind=HD.splineCurve.getPointAt(tBehind);
  var camX=posBehind.x+right.x*HD.steerX*0.4;
  var camZ=posBehind.z+right.z*HD.steerX*0.4;
  var camY=posBehind.y+camHeight;

  // Smooth camera with lag
  if(!HD.camPos)HD.camPos=new THREE.Vector3(camX,camY,camZ);
  HD.camPos.lerp(new THREE.Vector3(camX,camY,camZ),Math.min(1,4*delta));
  HD.camera.position.copy(HD.camPos);

  // Camera look at point ahead of vehicle
  var laT=Math.min(t+4/curveLen,0.999);
  var laPos=HD.splineCurve.getPointAt(laT);
  HD.camera.lookAt(new THREE.Vector3(
    laPos.x+right.x*HD.steerX*0.3,
    laPos.y+1,
    laPos.z+right.z*HD.steerX*0.3
  ));

  // FOV scales with speed
  var targetFov=65+((HD.speed-HD.baseSpeed)/(HD.maxSpeed-HD.baseSpeed))*15;
  HD.camera.fov+=(targetFov-HD.camera.fov)*2*delta;
  HD.camera.updateProjectionMatrix();

  // Move ground with player
  HD.ground.position.x=pos.x;
  HD.ground.position.z=pos.z;
  HD.ground.position.y=pos.y-3;

  // Move fog with player
  HD.scene.fog.near=150;
  HD.scene.fog.far=500;

  // HUD
  updateHUD();

  // Render
  HD.renderer.render(HD.scene,HD.camera);
}

window.hdashStop=function(){
  HD.active=false;
  if(HD.frameId)cancelAnimationFrame(HD.frameId);
  HD.frameId=null;
  if(HD._keydown)window.removeEventListener('keydown',HD._keydown);
  if(HD._keyup)window.removeEventListener('keyup',HD._keyup);
  if(HD._resize)window.removeEventListener('resize',HD._resize);
  var canvas=document.getElementById('hdash-canvas');
  if(canvas){
    canvas.removeEventListener('touchmove',HD._touchmove);
    canvas.removeEventListener('touchend',HD._touchend);
  }
  var hud=document.getElementById('hdashHud');
  if(hud)hud.style.display='none';
  // Clean up Three.js
  if(HD.renderer){HD.renderer.dispose()}
  if(HD.scene){
    HD.scene.traverse(function(obj){
      if(obj.geometry)obj.geometry.dispose();
      if(obj.material){
        if(Array.isArray(obj.material))obj.material.forEach(function(m){m.dispose()});
        else obj.material.dispose();
      }
    });
  }
  HD.scene=null;HD.renderer=null;HD.camera=null;
  HD.roadMeshes=[];HD.envObjs=[];
  HD.camPos=null;HD.keys={left:false,right:false};
};

})();

